window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q11"]=window.__LIBQ["tien-nghich"]["q11"]||{};window.__LIBQ["tien-nghich"]["q11"]["map"]={"updatedAt":"2026-07-12","count":138,"nodes":[{"id":"dai-luc-hoang-da-son-coc-tuong-da","name":"Đại lục hoang dã (sơn cốc tượng đá Vương Lâm)","cn":null,"capDo":"khac","parentId":null,"blurb":"Đại lục hoang dã nơi Lý Thiến Mai mười năm chăm sóc tượng đá Vương Lâm, có mãnh thú hoành hành.","detail":"Tượng đá Vương Lâm nằm trong một sơn cốc trên đại lục hoang dã. Lý Thiến Mai ở đây suốt mười năm dùng máu tươi, tinh huyết, đạo huyết nguyên thần vẽ lên tượng đá. Tượng đá đã hòa thành một với đại lục. Khi Vương Lâm thức tỉnh, lớp da đá sụp đổ, cả đại lục ầm ầm rời ra, những khe khổng lồ khiến đại lục hoang dã tan nát thành bốn năm mảnh. Trước khi rời đi, Lý Thiến Mai bố trí kiếm trận chín thanh phi kiếm bảo vệ sơn cốc.","theLucLienQuan":[],"nguon":["@c1214"]},{"id":"chien-truong-yeu-tong-khe-sau-nhat","name":"Chiến trường Yêu Tông (khe sâu nhất)","cn":null,"capDo":"khac","parentId":"chien-truong-nhat-duong-thien","blurb":"Khe sâu nhất trong chiến trường Yêu Tông, nơi dò xét thông đạo với giới ngoại, tràn ngập mãnh thú chí cường.","detail":"Khe sâu nhất của chiến trường nơi Yêu Tông yêu cầu Lý Thiến Mai đi vào để dò xét thông đạo với giới ngoại, đổi lại hồn huyết cứu Vương Lâm. Nơi đây có mãnh thú chí cường, ai vào coi như chắc chắn phải chết. Yêu Tông cố ý muốn Lý Thiến Mai chết tại đây để cảnh cáo những ai dám cãi lệnh. Vương Lâm sau khi thức tỉnh quyết đi tới chiến trường Yêu Tông để cứu nàng.","theLucLienQuan":["yeu-tong"],"nguon":["@c1214"]},{"id":"yeu-tong-tinh-vuc-cap-chin","name":"Yêu Tông tinh vực cấp chín","cn":null,"capDo":"tinh-cau","parentId":null,"blurb":"Tinh vực cấp chín nơi Yêu Tông đóng quân, Lý Thiến Mai bay về đây lấy hồn huyết.","detail":"Tinh vực cấp chín là nơi Yêu Tông đặt căn cứ. Lý Thiến Mai lần đầu tiên trong mười năm rời đại lục hoang dã, bay về đây để thu hồi hồn huyết của mình nhằm cứu tỉnh Vương Lâm. Yêu Tông ép nàng đáp ứng điều kiện đi vào khe sâu nhất chiến trường mới cho lấy hồn huyết.","theLucLienQuan":["yeu-tong"],"nguon":["@c1214"]},{"id":"tinh-vuc-cap-hai","name":"Tinh vực cấp hai","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực cấp hai, nơi Vương Lâm xuất phát, phóng xuyên qua để lại khe nứt khổng lồ phân chia cả tinh vực làm đôi.","detail":"Vương Lâm phóng xé tinh không với tốc độ kinh hoàng, thân ảnh lướt qua để lại khe nứt khổng lồ xé đôi tinh vực cấp hai. Không có truyền tống trận.","theLucLienQuan":[],"nguon":["@c1215"]},{"id":"tinh-vuc-cap-ba","name":"Tinh vực cấp ba","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực cấp ba, Vương Lâm xuyên qua trên đường tới Hải Hồn Tông.","detail":"Vương Lâm xuyên qua tinh vực cấp ba trên đường tới tinh vực cấp bốn. Không có truyền tống trận.","theLucLienQuan":[],"nguon":["@c1215"]},{"id":"tinh-vuc-cap-bon","name":"Tinh vực cấp bốn","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực cấp bốn, nơi đặt đại lục Hải Hồn Tông. Vương Lâm ép Hải Hồn Tông mở truyền tống trận tại đây.","detail":"Đại lục Hải Hồn Tông nằm ở tinh vực cấp bốn. Hải Hồn Tông xưng hùng cả tinh vực này, sở hữu truyền tống trận kết nối tới tinh vực cấp sáu. Vương Lâm cưỡng phá đại trận phòng hộ và ép mở truyền tống trận tại đây.","theLucLienQuan":["Hải Hồn Tông"],"nguon":["@c1215"]},{"id":"tinh-vuc-cap-tam","name":"Tinh vực cấp tám","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực cấp tám, nơi đặt Vô Cực Tông và Tịch Hồn Đạo.","detail":"Nơi đặt Vô Cực Tông và Tịch Hồn Đạo. Vô Cực Tông có truyền tống trận tới tinh vực cấp chín.","theLucLienQuan":["Vô Cực Tông","Tịch Hồn Đạo"],"nguon":["@c1215"]},{"id":"son-mon-vo-cuc-tong","name":"Sơn môn Vô Cực Tông (ngọn núi thanh kiếm Cổ Thần)","capDo":"khac","parentId":"tu-chan-tinh","blurb":"Ngọn núi hùng vĩ nằm trong lãnh địa Vô Cực Tông, do thanh kiếm Cổ Thần hóa thành, bên trong phong ấn pho tượng Cổ Thần.","detail":"Ngọn núi tại sơn môn Vô Cực Tông do thanh kiếm Cổ Thần hóa thành. Khi Vương Lâm kích hoạt Cổ Thần lực, núi nứt vỡ, bụi bay mù mịt, thiên địa biến sắc. Bên trong hiện pho tượng Cổ Thần giãy giụa gào thét.","theLucLienQuan":["Vô Cực Tông"],"nguon":["@c1217"]},{"id":"tang-thu-chin-van-hai","name":"Tầng thứ chín Vân Hải tinh vực","cn":"","capDo":"vuc","parentId":"van-hai-tinh","blurb":"Tầng sâu nhất của Vân Hải tinh vực, sương mù dày đặc, có mãnh thú cấp mười hai. Thần Tông và Yêu Tông đều đặt tại tầng này.","detail":"Vương Lâm lần đầu bước vào sau khi khai phá tầng thứ tám. Sương mù dày đặc bao phủ, mãnh thú cấp mười hai ẩn trong sương. Thần Tông đặt mật thất tại đây, Yêu Tông phòng thủ cái khe chiến trường tại đây.","theLucLienQuan":["Thần Tông","Yêu Tông"],"nguon":["@c1219"]},{"id":"mat-that-than-tong","name":"Mật thất Thần Tông (tầng thứ chín)","cn":"","capDo":"khac","parentId":"tang-thu-chin-van-hai","blurb":"Mật thất trong Thần Tông tại tầng thứ chín, nơi Thủy Đạo Tử ngồi chịu thống khổ sinh tử suốt mười năm.","detail":"Thủy Đạo Tử khoanh chân trong mật thất, toàn thân phát ánh sáng bảy màu, dung nhan lão hóa rồi nghịch chuyển liên tục.","theLucLienQuan":["Thần Tông"],"nguon":["@c1219"]},{"id":"cuu-u-tham-uyen","name":"Cửu U Thâm Uyên","cn":"九幽深渊","capDo":"khac","parentId":null,"blurb":"Nơi xuất xứ của Cửu U Long, được nhắc đến qua lời ba tu sĩ Yêu Tông tại chiến trường khe nứt.","detail":"Nơi Cửu U Long sinh sống, ấu long từ đây xuất hiện tại chiến trường Yêu Tông. Vị trí cụ thể chưa rõ.","theLucLienQuan":[],"nguon":["@c1220"]},{"id":"khe-chien-truong-yeu-tong","name":"Khe chiến trường Yêu Tông","cn":"","capDo":"khac","parentId":"yeu-tong-tinh-vuc-cap-chin","blurb":"Khe nứt là lối đi giữa hai thế giới, bên trong có mãnh thú, vương thú, hoàng thú. Được tông chủ Yêu Tông phong ấn thu nhỏ nhưng không hoàn toàn. Cửu U Long trú ngụ bên trong.","detail":"Khe chiến trường nằm trong tinh vực cấp chín Yêu Tông, bên trong có các loại mãnh thú hùng mạnh. Tông chủ đời đầu Yêu Tông đã phong ấn thu nhỏ khe nhưng có kẻ bên trong ngăn cản khiến phong ấn không hoàn toàn. Sáu tu chân tinh xếp hình tròn tạo đại trận bảo vệ bên ngoài khe. Vương Lâm dùng tay xé rách khe để vào tìm Lý Thiến Mai.","theLucLienQuan":["Yêu Tông"],"nguon":["@c1221"]},{"id":"sau-tu-chan-tinh-yeu-tong","name":"Sáu tu chân tinh Yêu Tông","cn":"","capDo":"tinh-cau","parentId":"yeu-tong-tinh-vuc-cap-chin","blurb":"Sáu ngôi sao xếp hình tròn tạo đại trận, mỗi sao có một sơn môn với trưởng lão trấn giữ, hoạt động gần như độc lập.","detail":"Sáu tu chân tinh của Yêu Tông xếp hình tròn tạo thành đại trận pháp ngăn mãnh thú từ khe chiến trường. Mỗi tu chân tinh có một sơn môn riêng với trưởng lão trấn giữ, hoạt động gần như độc lập. Trên mỗi sơn môn đều có bia đá khắc hình tông chủ đời đầu.","theLucLienQuan":["Yêu Tông"],"nguon":["@c1221"]},{"id":"khe-nut-chien-truong-ben-trong","name":"Khe nứt chiến trường Yêu Tông (bên trong)","cn":"","capDo":"gioi-nho","parentId":"khe-chien-truong-yeu-tong","blurb":"Thế giới tối đen khổng lồ bên trong khe nứt chiến trường Yêu Tông, tựa một tinh không khác, chứa vô số mãnh thú.","detail":"Không gian tối đen khổng lồ tựa một tinh không khác. Tu vi cao cũng chỉ nhìn rõ trong phạm vi trăm trượng. Không có ban ngày, không cảm nhận được thời gian. Chứa vô số mãnh thú (phần lớn cấp tám cấp chín, cấp mười trở lên ít). Tồn tại những luồng khí tức cực kỳ hùng mạnh nhưng không ngăn cản Vương Lâm đi qua.","theLucLienQuan":["Yêu Tông"],"nguon":["@c1223"]},{"id":"khe-nut-tu-gioi","name":"Khe nứt Tử Giới","cn":"紫界","capDo":"gioi-nho","parentId":"khe-nut-chien-truong-ben-trong","blurb":"Khu vực nằm sâu hơn trong khe nứt chiến trường, thế giới chuyển từ tối đen sang màu tím, nơi Vương Lâm tìm được manh mối đầu tiên về Lý Thiến Mai.","detail":"Khu vực biên giới nằm sâu hơn trong khe nứt chiến trường Yêu Tông, gần điểm tận cùng thông đạo trong ngọc giản. Thế giới chuyển từ tối đen sang màu tím. Cửu U Long (vương thú) run rẩy sợ hãi khi vào nơi này. Mãnh thú từ bên ngoài không dám vào nhưng có mãnh thú bản địa sống tại đây. Tại biên giới khu vực này, Vương Lâm cảm nhận được dao động thần thông còn sót lại và dùng Tuế Nguyệt Nghịch Chuyển nhìn thấy ảo ảnh quá khứ của nữ tử áo lam (nghi Lý Thiến Mai).","theLucLienQuan":["Yêu Tông"],"nguon":["@c1223"]},{"id":"vung-bang-han-khe-nut-tim","name":"Vùng băng hàn khe nứt tím","cn":"","capDo":"khac","parentId":"khe-nut-chien-truong-ben-trong","blurb":"Vùng sâu nhất bên trong khe nứt tím, tràn ngập khí tức băng hàn thấu xương có thể làm chậm cả nguyên thần. Mãnh thú bạch khí ở đây mạnh hơn hẳn bên ngoài, vô số không đếm được. Là cấm địa mà Cửu U Long không dám bước vào.","detail":"Nằm ở cuối thông đạo được chỉ dẫn trong ngọc giản bản đồ khe nứt. Khí tức băng hàn xâm nhập cơ thể thấu xương, mãnh thú ở đây bao phủ bạch khí, mạnh hơn hẳn những loại bên ngoài. Cửu U Long — vương thú — cảm nhận được khí tức này và hoảng sợ không dám tiến thêm, coi nơi đây như cấm địa. Lý Thiến Mai bị mắc kẹt giao chiến sống còn với hư ảnh tiên tử tại vùng này.","theLucLienQuan":[],"nguon":["@c1224"]},{"id":"khe-nut-the-gioi-mau-tim","name":"Khe nứt thế giới màu tím","cn":"","capDo":"khac","parentId":"khe-nut-chien-truong-ben-trong","blurb":"Không gian bên trong khe nứt, thế giới tối đen tràn ngập sắc tím, vô biên vô hạn, toàn bộ là mãnh thú.","detail":"Thế giới màu tím bên trong khe nứt chiến trường Yêu Tông, không gian tối đen tràn ngập sắc tím, có khí tức vô hình lạnh như băng và dòng chảy ngầm cuốn động phong vân gây dị biến. Vô biên vô hạn, khắp nơi đều là mãnh thú bao gồm hơn vạn Văn thú và mãnh thú cấp cao (có con thân hình vạn trượng). Xuất hiện hư ảnh chiếc roi bí ẩn chứa sức mạnh vượt quy tắc.","theLucLienQuan":[],"nguon":["@c1225"]},{"id":"that-thai-gioi","name":"Thất Thải giới","cn":"七彩界","capDo":"gioi-nho","parentId":null,"blurb":"Nơi Vương Lâm bị phong ấn tu vi hai ngàn năm trước.","detail":"Tiểu thế giới nơi Vương Lâm từng bị phong ấn tu vi bằng cấm chế phức tạp hai ngàn năm trước. Tới chương 1225, Vương Lâm tự tay mở phong ấn cấm chế trên mi tâm để giải phóng toàn bộ tu vi.","theLucLienQuan":[],"nguon":["@c1225"]},{"id":"te-dan-co-than","name":"Tế đàn của Cổ Thần","cn":"","capDo":"khac","parentId":"khe-nut-chien-truong-ben-trong","blurb":"Tế đàn của Cổ Thần nằm sâu trong khe nứt, Y Nguyệt hứa dẫn Vương Lâm tới như phần thưởng liên minh.","detail":"Y Nguyệt tiết lộ sâu trong khe nứt có một tế đàn của Cổ Thần, dùng làm phần thưởng mời Vương Lâm kết đồng minh. Chưa rõ công dụng cụ thể nhưng Y Nguyệt tỏ ra chắc chắn Vương Lâm sẽ động tâm.","theLucLienQuan":["Cổ Thần"],"nguon":["@c1228"]},{"id":"phong-gioi-dai-tran-hu-vo","name":"Phong Giới Đại Trận (hư vô)","cn":"封界大阵","capDo":"khac","parentId":"phong-gioi","blurb":"Vùng hư vô nằm phía dưới tinh không, chứa đại trận dạng mạng lưới vô biên bao vây thiên địa giới nội, phân chia giới nội và giới ngoại.","detail":"Khi Vương Lâm dùng huyết kiếm xé tinh không phía dưới, khe nứt mở ra lộ vùng hư vô — nơi Phong Giới Đại Trận ẩn mình. Đại trận dạng mạng lưới sáng ngời, vô biên vô hạn, bao vây cả thiên địa giới nội. Vương Lâm bước vào đây, hóa thành lạc ấn dùng thân chống đỡ núi mây và truyền lực thiên kiếp lên mạng lưới.","theLucLienQuan":[],"nguon":["@c1231"]},{"id":"vung-dat-uoc-mo","name":"Vùng đất ước mơ","cn":"","capDo":"khac","parentId":null,"blurb":"Thế giới hỗn độn bên trong dòng xoáy bốn kiếm thiên kiếp, có tinh cầu và con người, phát tiếng gọi hứa trường sinh thoát luân hồi, hút tu sĩ đạo tâm bất ổn vào.","detail":"Khi bốn kiếm thiên kiếp xoay tròn, dòng xoáy hình thành chứa thế giới hỗn độn bên trong, có thể thấy tinh cầu và con người. Phát ra tiếng gọi mê hoặc hứa trường sinh, thoát luân hồi, muốn gì được nấy, xuyên thấu mọi đại trận phòng hộ trong tinh vực cấp chín. Tu sĩ đạo tâm bất ổn bị lôi vào, đồng tử tan ra nở cười rồi biến mất. Thái thượng trưởng lão Yêu Tông gọi đây là vùng đất ước mơ trong vô lượng kiếp.","theLucLienQuan":[],"nguon":["@c1231"]},{"id":"ma-nap-tinh","name":"Ma Nạp Tinh","cn":"","capDo":"tu-chan-tinh","parentId":"thai-co-tinh-than","blurb":"Tu chân tinh tối đen ở Thái Cổ Tinh Thần, nhiều ao đầm, linh khí nồng đậm, tràn ngập oán khí, có nhiều tu sĩ và linh thú cư trú.","detail":"Tu chân tinh tối đen, nhiều ao đầm, linh khí nồng đậm, tràn ngập oán khí. Có nhiều tu sĩ và linh thú sinh sống. Bị Vương Lâm tấn công, dùng sương đen hóa mấy vạn phần nuốt toàn bộ tu sĩ. Lão giả áo xanh lục (đại thần thông, thiên nhân đệ nhất suy) là tu sĩ mạnh nhất trên tinh, bị giết.","theLucLienQuan":[],"nguon":["@c1237"]},{"id":"tinh-vuc-nguyet-toc","name":"Tinh vực Nguyệt Tộc","cn":"月族星域","capDo":"vuc","parentId":"thai-co-tinh-than","blurb":"Tinh vực nơi Nguyệt Tộc cư ngụ trong Thái Cổ Tinh Thần, cách vị trí Vương Lâm cực xa, cần mấy lần Súc Địa Thành Thốn mới tới.","detail":"Nơi Nguyệt Tộc cư ngụ, cao thủ như mây, là long đàm hổ huyệt. Vương Lâm biết vị trí nhờ ký ức của tu sĩ cùng người Nguyệt Tộc năm xưa ở Thất Thải Giới.","theLucLienQuan":["Nguyệt Tộc"],"nguon":["@c1238"]},{"id":"lam-ti-tinh-vuc","name":"Lam Ti tinh vực","capDo":"tinh-cau","parentId":"thai-co-tinh-than","blurb":"Tinh vực cực kỳ rộng lớn, xinh đẹp, mỗi tu chân tinh tỏa ra màu lam nhu hòa. Nơi tương đối hẻo lánh trong tinh hải, địa bàn của Lam Ti tộc.","detail":"Tinh vực do Lam Ti tộc chiếm cứ, nằm ở vị trí tương đối hẻo lánh trong tinh hải Thái Cổ Tinh Thần. Mỗi tu chân tinh trong tinh vực tỏa ra ánh sáng lam nhu hòa. Vương Lâm ôm Lý Thiến Mai dùng Súc Địa Thành Thốn và Na Di xuyên tinh không tới nơi đây tìm Lam Mộng Đạo Tôn cứu chữa.","theLucLienQuan":["Lam Ti tộc"],"nguon":["@c1240"]},{"id":"tu-chan-tinh-lam-mong-dao-ton","name":"Tu chân tinh của Lam Mộng Đạo Tôn","cn":"","capDo":"tinh-cau","parentId":"lam-ti-tinh-vuc","blurb":"Tu chân tinh riêng của Lam Mộng Đạo Tôn, nằm trong tinh hải Lam Ti tộc, tỏa ánh sáng màu lam.","detail":"Tu chân tinh nằm trong tinh hải của Lam Ti tộc, toàn bộ tỏa ánh sáng màu lam. Bên trong là một mảnh hải dương màu lam, có đội thuyền ngoài khơi và tiếng nhạc vui vẻ. Lam Sơn tọa lạc trên tu chân tinh này, nơi Lam Mộng Đạo Tôn cư ngụ và chữa trị cho Lý Thiến Mai.","theLucLienQuan":["lam-ti-toc"],"nguon":["@c1241"]},{"id":"bien-gioi-tinh-vuc-lam-ti-toc","name":"Biên giới tinh vực Lam Ti tộc","cn":"","capDo":"khac","parentId":"lam-ti-tinh-vuc","blurb":"Khu vực tinh không ở bờ ngoài tinh vực Lam Ti tộc, nơi Vương Lâm phát hiện bạch y nữ tử bí ẩn bám theo mình.","detail":"Tinh không ánh sáng như ngọc, an tĩnh, trong vẻ đẹp lộ ra cảm giác quỷ dị. Bạch y nữ tử không có sinh cơ tung bay tại đây nhưng không tiến vào trong phạm vi Lam Ti tộc.","theLucLienQuan":["Lam Ti tộc"],"nguon":["@c1242"]},{"id":"tu-chan-tinh-bien-gioi-lam-ti","name":"Tu chân tinh gần biên giới Lam Ti tộc","cn":"","capDo":"tinh-cau","parentId":"lam-ti-tinh-vuc","blurb":"Tinh cầu màu lam ở bờ tinh vực Lam Ti tộc, nơi Vương Lâm đả tọa thổ nạp sau khi phát hiện bạch y nữ tử.","detail":"Tinh cầu màu lam, hải dương chiếm phân nửa, có ngọn núi gió gào thét mang hơi lạnh. Vương Lâm đả tọa bảy ngày phân tích manh mối rồi ở lại thổ nạp một tháng, khôi phục tu vi tới đỉnh phong.","theLucLienQuan":["Lam Ti tộc"],"nguon":["@c1242"]},{"id":"tu-chan-tinh-lam-ti-toc","name":"Tu chân tinh Lam Ti Tộc","cn":"","capDo":"tinh-cau","parentId":"thai-co-tinh-than","blurb":"Tu chân tinh trong tinh vực Lam Ti Tộc, nơi Vương Lâm ngồi trên đỉnh núi cảm ngộ tam đại thần thông.","detail":"Tu chân tinh nằm trong tinh vực Lam Ti Tộc thuộc Thái Cổ Tinh Thần. Trải qua mùa mưa kéo dài nửa năm rồi chuyển sang mùa đông lạnh giá, mặt đất đóng băng ngàn dặm, tuyết phủ trắng xóa. Vương Lâm ngồi trên đỉnh núi phủ tuyết, tản thần thức bao trùm toàn bộ tu chân tinh để cảm ngộ thần thông.","theLucLienQuan":["Lam Ti Tộc"],"nguon":["@c1245"]},{"id":"tinh-vuc-ma-hat-toc","name":"Tinh vực Ma Hạt Tộc","cn":"","capDo":"vuc","parentId":"thai-co-tinh-than","blurb":"Khu vực phía tây bắc Thái Cổ Tinh Thần, nơi cư ngụ của Ma Hạt Tộc. Bạch Y Nữ Tử chạy tới đây cầu viện Ma Hạt Tộc ngăn cản Vương Lâm.","detail":"Tinh vực nằm ở phía tây bắc Thái Cổ Tinh Thần, là lãnh địa của Ma Hạt Tộc với một tu chân tinh làm căn cứ. Phân thân Lan Phi bị Vương Lâm truy sát đã chạy tới đây kêu gọi mấy ngàn tu sĩ Ma Hạt Tộc ra ngăn cản.","theLucLienQuan":["Ma Hạt Tộc"],"nguon":["@c1250"]},{"id":"thiem-loi-toc-dia-ban","name":"Thiểm Lôi Tộc (địa bàn)","cn":"闪雷族","capDo":"khac","parentId":"thai-co-tinh-than","blurb":"Địa bàn của Thiểm Lôi Tộc trong Thái Cổ Tinh Thần, nơi tồn tại đạo thiểm điện vạn năm bất diệt là thánh vật và nguồn suối sức mạnh toàn tộc.","detail":"Thiểm Lôi Tộc cư trú trong Thái Cổ Tinh Thần, trong tộc không có tu sĩ Đệ Tam Bộ. Nơi đây sở hữu thánh vật là đạo thiểm điện vạn vạn năm bất diệt, thủy chung xuyên qua trời đất, là nguồn suối sức mạnh của toàn tộc. Vương Lâm từ trí nhớ tu sĩ bị cắn nuốt biết được vị trí Thiểm Lôi Tộc, nhắm nuốt đạo thiểm điện để lôi bổn nguyên tiến thêm bước lớn.","theLucLienQuan":["thiem-loi-toc"],"nguon":["@c1251"]},{"id":"phia-dong-thai-co-tinh-than","name":"Phía đông Thái Cổ Tinh Thần","cn":null,"capDo":"khac","parentId":"thai-co-tinh-than","blurb":"Khu vực phía đông Thái Cổ Tinh Thần, nơi Bạch Y Nữ Tử na di tới sau khi thoát khỏi trận chiến.","detail":"Bạch Y Nữ Tử dùng lần na di cuối cùng thoát tới phía đông Thái Cổ Tinh Thần, thân thể dần trong suốt sắp biến mất. Vương Lâm truy kích tới nơi này, thi triển Định Thần Thuật đóng băng trời đất, kéo nàng ra khỏi hư vô và giết chết tại đây.","theLucLienQuan":[],"nguon":["@c1251"]},{"id":"loi-tri-thiem-loi-toc","name":"Lôi trì Thiểm Lôi Tộc","cn":"","capDo":"vuc","parentId":"thiem-loi-toc-dia-ban","blurb":"Tinh vực mênh mông của Thiểm Lôi Tộc trong Thái Cổ Tinh Thần, tràn ngập sấm sét, giống lôi trì khổng lồ tồn tại từ viễn cổ.","detail":"Vùng biên giới trăm dặm đã đầy lực lượng sấm sét. Ai không có lệnh bài mà xâm nhập sẽ bị hàng ngàn vạn sấm sét tấn công. Vương Lâm nhờ đã ngộ lôi bản nguyên nên xâm nhập thành công và dung hợp hoàn toàn với lôi trì.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1252"]},{"id":"dai-luc-van-tan","name":"Đại lục Vân Tàn","cn":"云残","capDo":"khac","parentId":"loi-tri-thiem-loi-toc","blurb":"Mảnh đại lục đổ nát màu đen nằm ở trung tâm vòng tròn mười sáu tu chân tinh, thánh địa Thiểm Lôi Tộc.","detail":"Không có sinh cơ, trên đó có miếu thờ thông thiên bị một luồng tia chớp màu đen (bên trong nhiều màu) từ hư vô đánh liên tục suốt vài ngàn năm không ngừng. Cấm địa được lịch đại đại trưởng lão thủ hộ.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1252"]},{"id":"tu-chan-tinh-mau-vang","name":"Tu chân tinh màu vàng","cn":"","capDo":"tinh-cau","parentId":"loi-tri-thiem-loi-toc","blurb":"Một trong mười sáu tu chân tinh của Thiểm Lôi Tộc, bao phủ sấm sét, xây dựng ngàn vạn động phủ là nơi tu hành của tộc nhân trưởng thành.","detail":"Nơi thanh niên hắc y bị thương và bị Vương Lâm đoạt xá thân xác qua tia chớp.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1252"]},{"id":"mieu-tho-thong-thien-van-tan","name":"Miếu thờ thông thiên (Vân Tàn)","cn":"","capDo":"khac","parentId":"dai-luc-van-tan","blurb":"Miếu thờ trên đại lục Vân Tàn, được xây trong vùng sấm sét, cấm địa Thiểm Lôi Tộc.","detail":"Miếu thờ được lịch đại đại trưởng lão thủ hộ, bị tia chớp đen (nhiều màu bên trong) từ hư vô đánh liên tục suốt vài ngàn năm không ngừng, ẩn chứa bí mật truyền thừa hoặc phong ấn cổ xưa.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1252"]},{"id":"tu-chan-tinh-vu-phi","name":"Tu chân tinh Vu Phi ở","cn":null,"capDo":"tinh-cau","parentId":"thiem-loi-toc-dia-ban","blurb":"Một trong 13 tu chân tinh rèn luyện của Thiểm Lôi Tộc, nơi Vương Lâm đoạt xá Vu Phi và chiếm động phủ Tề Trì.","detail":"Tinh cầu rất lớn thuộc hệ thống 16 tu chân tinh màu vàng của Thiểm Lôi Tộc (trừ 3 mẫu tinh đông đúc, 13 tinh cầu còn lại là nơi rèn luyện tộc nhân). Có sơn cốc chứa linh mạch, dòng sông nhỏ, linh thảo và cây lôi quả. Vương Lâm dùng phân thân nguyên thần đoạt xá thân thể Vu Phi tại đây, sau đó chiếm lại động phủ truyền thừa của Vu Phi từ tay Tề Trì.","theLucLienQuan":["thiem-loi-toc"],"nguon":["@c1253"]},{"id":"dong-phu-truyen-thua-vu-phi","name":"Động phủ truyền thừa Vu Phi","cn":null,"capDo":"khac","parentId":"tu-chan-tinh-vu-phi","blurb":"Động phủ nằm trong sơn cốc vùng linh mạch, từng bị Tề Trì chiếm, sau được Vương Lâm đoạt lại.","detail":"Nằm trong sơn cốc vùng linh mạch trên tu chân tinh rèn luyện. Có sáu thạch thất, dòng sông nhỏ nước trong vắt, trồng nhiều linh thảo, cây lôi quả trên vách đá (còn sáu quả). Trận pháp chạm khắc trên nóc động phủ có thể mở ra nhìn bầu trời, tường đá trở nên trong suốt — Vương Lâm đánh giá thô sơ nhưng có chỗ tinh diệu. Nhiều cấm chế bảo vệ, tất cả tự mở ra khi Vương Lâm bước vào. Vốn là động phủ truyền thừa của Vu Phi ở vùng linh mạch, bị tu sĩ Nguyên Anh sơ kỳ Tề Trì cướp đoạt ngay ngày thứ ba sau khi Vu Phi thừa kế.","theLucLienQuan":["thiem-loi-toc"],"nguon":["@c1253"]},{"id":"thanh-dia-thiem-loi-toc","name":"Thánh địa Thiểm Lôi Tộc","cn":null,"capDo":"khac","parentId":"thiem-loi-toc-dia-ban","blurb":"Nơi chứa sấm sét bất diệt, mỗi trăm năm chỉ một người được vào tiếp xúc.","detail":"Thánh địa của Thiểm Lôi Tộc, nơi tồn tại luồng sấm sét bất diệt đã có từ muôn đời. Cứ mỗi trăm năm, người đứng đầu Thiểm Lôi Bảng (bảng xếp hạng 800 người theo Lôi Tinh trên 13 tu chân tinh) được vào tiếp xúc sấm sét bất diệt để mở rộng tộc ấn và tăng tu vi. Đây là mục tiêu cuối cùng của Vương Lâm trong kế hoạch trà trộn Thiểm Lôi Tộc dưới danh tính Vu Phi, còn bảy năm nữa sẽ diễn ra tranh đoạt.","theLucLienQuan":["thiem-loi-toc"],"nguon":["@c1253","@c1274"]},{"id":"son-mon-thien-loi-tong","name":"Sơn môn Thiên Lôi Tông","cn":"天雷宗山门","capDo":"khac","parentId":"thiem-loi-toc-dia-ban","blurb":"Sơn môn của Thiên Lôi Tông, nằm trên tu chân tinh Thiểm Lôi Tộc.","detail":"Ngọn núi không cao, mây phủ đầy, có con đường đá uốn lượn từ đỉnh xuống. Trên đỉnh có lầu các và quảng trường đại điện. Nơi bốn trưởng lão Nguyên Anh bị Vương Lâm phế ký hiệu và ném xuống quảng trường.","theLucLienQuan":["Thiên Lôi Tông"],"nguon":["@c1254"]},{"id":"loi-tien-dao-dia-ban","name":"Lôi Tiên Đạo (sơn môn)","cn":"","capDo":"khac","parentId":"thiem-loi-toc-dia-ban","blurb":"Sơn môn tông phái Lôi Tiên Đạo, cách vị trí Thiên Lôi Tông mười vạn dặm trên tinh cầu Thiểm Lôi Tộc.","detail":"Nơi đóng đô của tông phái Lôi Tiên Đạo trên tinh cầu Thiểm Lôi Tộc, cách vị trí hiện tại của Hứa Lập Quốc mười vạn dặm. Có nhiều nữ tu, tông chủ xinh đẹp tuyệt trần tu vi khá cao. Mục tiêu tiếp theo của Hứa Lập Quốc.","theLucLienQuan":["Lôi Tiên Đạo"],"nguon":["@c1256"]},{"id":"loi-tinh-dien","name":"Lôi Tinh Điện","cn":"","capDo":"khac","parentId":"thiem-loi-toc-dia-ban","blurb":"Nơi có thể đổi Lôi tinh trong địa bàn Thiểm Lôi Tộc, sắp mở cửa.","detail":"Chung Đại Hồng đề nghị Vương Lâm đi đến Lôi Tinh Điện sắp mở cửa để đổi Lôi tinh từ vật phẩm đã sưu tầm.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1257"]},{"id":"vu-di-son-map","name":"Vũ Di Sơn","cn":"巫夷山","capDo":"khac","parentId":"thiem-loi-toc-dia-ban","blurb":"Nơi cư ngụ của Hắc Ma Pháp Vương và Tứ vương, đều là lão quái Vấn Đỉnh, nằm trong phạm vi tu chân tinh Thiểm Lôi Tộc.","detail":"Vũ Di Sơn là nơi Hắc Ma Pháp Vương và Tứ vương cư ngụ. Cả bốn vương đều là lão quái đạt cảnh giới Vấn Đỉnh.","theLucLienQuan":["Vũ Di Sơn"],"nguon":["@c1258"]},{"id":"ao-den-cua-dong-loi-tinh-dien","name":"Ao đen (cửa đông Lôi Tinh Điện)","cn":"","capDo":"khac","parentId":"loi-tinh-dien","blurb":"Ao đen kịt chứa bùn nhão tại cửa đông Lôi Tinh Điện, nơi đổi vật phẩm lấy Lôi tinh.","detail":"Ao đen kịt chứa bùn nhão, liên tục nổi bọt khí. Vật phẩm ném vào bị thôn phệ, sau đó ao xử lý và trả lại ngọc giản đã ghi chép số lượng Lôi tinh tương ứng. Ba lão già tu vi Dương Thực và Âm Hư canh giữ bên cạnh.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1259"]},{"id":"khe-nut-suong-mu-sam-set","name":"Khe nứt sương mù sấm sét","cn":"","capDo":"khac","parentId":"loi-tinh-dien","blurb":"Lối vào Lôi Tinh Điện, hai bên là sương mù xanh thực chất là sấm sét hóa thành bằng thuật Hóa Lôi Vi Vụ.","detail":"Khe nứt dẫn đến Lôi Tinh Điện, đi xuyên mất nửa nén hương. Hai bên là sương mù màu xanh liên tục chuyển động, thực chất là sấm sét được hút từ Lôi vực rồi bóp nát thành sương mù bằng thuật đại thần thông Hóa Lôi Vi Vụ, có tác dụng phòng hộ. Thiểm Lôi Tộc chưa từng ngờ có người xâm nhập qua đây.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1259"]},{"id":"bay-tram-van-thien-dia","name":"Bảy trăm vạn thiên địa","cn":"七百万天地","capDo":"gioi-dien","parentId":"thai-co-tinh-than","blurb":"Vùng đất do tổ tiên Thiểm Lôi Tộc cùng Đệ Tam Bộ đại năng tạo ra, chứa bảy trăm vạn thế giới có sinh linh tu luyện.","detail":"Bảy trăm vạn thiên địa là bảy trăm vạn thế giới do tổ tiên Thiểm Lôi Tộc và Đệ Tam Bộ đại năng tạo ra. Trong đó tuyệt đối không cho phép tu sĩ cấp bậc cao — đạt Hóa Thần đỉnh phong sẽ bị thiên kiếp giáng xuống. Sinh linh bên trong bị ép tin có Tiên giới. Bảo vật quý nhất của Thiểm Lôi Tộc dung nhập vào đại trận Phong giới nơi đây. Thiên đạo và thiên kiếp chỉ là nhiệm vụ trong Lôi Tinh Điện.","theLucLienQuan":["Thiểm Lôi Tộc","Đệ Tam Bộ"],"nguon":["@c1260"]},{"id":"cua-tay-loi-tinh-dien","name":"Cửa tây Lôi Tinh Điện","cn":"","capDo":"khac","parentId":"loi-tinh-dien","blurb":"Khu vực bên trong Lôi Tinh Điện dành cho nhiệm vụ cấp cao, rất ít tu sĩ.","detail":"Cửa tây là khu vực trong Lôi Tinh Điện dành cho các nhiệm vụ cấp cao. Rất ít tu sĩ lui tới. Không gian rộng như hư vô, bốn phía sấm sét bao phủ, có sáu lão già Âm Dương Hư Thực ngồi trấn giữ. Trên trăm ngọc giản nhiệm vụ lơ lửng giữa không trung, mỗi cái bùng thanh quang mạnh yếu khác nhau tương ứng với độ khó nhiệm vụ.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1260"]},{"id":"bay-tram-van-thien-dia-noi-khu","name":"Bảy trăm vạn thiên địa (nội khu)","cn":"七百万天地","aliases":["Thất bách vạn thiên địa"],"capDo":"khac","parentId":"bay-tram-van-thien-dia","blurb":"Không gian đặc biệt trong Thiểm Lôi Tộc, vào qua ngọc giản tại cửa Tây. Có cấm chế chặn thần thức, ngay cả lão tổ tông cũng không thể thăm dò.","detail":"Con đường vào dài và nhỏ, có hào quang chiếu cho thân thể trong suốt, bức tường lực cản khủng bố chặn thần thức bùng ra ngoài, nhiều không gian loạn lưu. Là nơi tu sĩ đại thần thông giải quyết ân oán cá nhân và giao dịch bí mật, kẻ mạnh là vua, giết người không ai biết.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1261"]},{"id":"quang-truong-trung-tam-bay-tram-van-thien-dia","name":"Quảng trường trung tâm bảy trăm vạn thiên địa","cn":"","capDo":"khac","parentId":"bay-tram-van-thien-dia","blurb":"Mảnh đại lục khổng lồ nằm giữa tinh không bảy trăm vạn thiên địa, nơi tất cả tộc nhân nhận nhiệm vụ phải xuất hiện.","detail":"Có pho tượng khổng lồ một nam một nữ toàn thân tràn ngập sấm sét nhìn phương xa, lầu các cao ngất, nhiều truyền tống trận, hơn mấy vạn tu sĩ qua lại. Tu sĩ hầu hết Anh Biến, nhiều Vấn Đỉnh, vài Âm Dương Hư Thực.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1262"]},{"id":"tan-cung-the-gioi","name":"Tận cùng thế giới","cn":null,"capDo":"khac","parentId":"bay-tram-van-thien-dia","blurb":"Nơi rìa bảy trăm vạn thiên địa, địa điểm Tán Linh mời Vương Lâm đến để cùng thực hiện kế hoạch phá vỡ lao ngục.","detail":"Địa điểm nằm ở rìa ngoài cùng của bảy trăm vạn thiên địa, nơi tiếp giáp với lồng vô hình ngăn cách thế giới với tinh không bên ngoài. Tán Linh mời Vương Lâm phá vỡ hư không xuyên qua bảy trăm vạn thiên địa phóng về phương này, dự kiến là điểm then chốt cho kế hoạch phá vỡ thiên địa bước vào tinh không.","theLucLienQuan":[],"nguon":["@c1267"]},{"id":"tan-cung-bay-tram-van-thien-dia","name":"Tận cùng bảy trăm vạn thiên địa (bức tường ngăn cách)","capDo":"khac","parentId":"bay-tram-van-thien-dia","blurb":"Nơi cuối cùng của bảy trăm vạn thiên địa, có sương mù bao phủ và một tầng màn chắn khổng lồ giống bức tường cao vô tận bao trùm thiên địa.","detail":"Nơi tận cùng của bảy trăm vạn thiên địa, cực kỳ yên tĩnh, sương mù bao phủ. Phía sau sương mù là một tầng màn chắn khổng lồ giống bức tường cao đến vô tận bao trùm thiên địa, tu sĩ đứng trước chỉ nhỏ như hạt bụi. Thanh niên đầu láng (Tán Linh Thượng Nhân) đã bay xuyên qua bảy trăm vạn thiên địa để đến đây, và trước bức tường này mọi ý niệm trốn tránh tan vỡ, hắn quyết tâm phản kháng.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1268"]},{"id":"lanh-dia-thiem-loi-toc","name":"Lãnh địa Thiểm Lôi Tộc","cn":"","capDo":"khac","parentId":"thiem-loi-toc-dia-ban","blurb":"Lãnh địa của Thiểm Lôi Tộc, được lôi vực vô tận bao quanh, có mười sáu tu chân tinh. Nơi diễn ra cuộc truy sát Hứa Lập Quốc và Vương Lâm xuất hiện giết trưởng lão Tịnh Niết.","detail":"Lãnh địa Thiểm Lôi Tộc được lôi vực vô tận bao quanh, bên trong có mười sáu tu chân tinh. Kinh biến xảy ra trên một trong mười sáu tu chân tinh khi Hứa Lập Quốc bắt cóc con nuôi cường giả và bị truy kích.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1269"]},{"id":"thai-co-loi-gioi","name":"Thái Cổ Lôi Giới","cn":"太古雷界","capDo":"gioi-nho","parentId":null,"blurb":"Lôi giới thái cổ nơi hồn phách các Thái Cổ Lôi Long trưởng thành đã chết tồn tại, được đại trưởng lão Thiểm Lôi Tộc mở ra bằng máu tu vi Đệ Ngũ Suy làm vật dẫn.","detail":"Không gian cổ xưa chứa hồn phách của các Thái Cổ Lôi Long trưởng thành đã chết từ thời thái cổ. Đại trưởng lão Thiểm Lôi Tộc dùng bí thuật Thái Cổ Lôi Giới, lấy máu tu vi Thiên Nhân Đệ Ngũ Suy làm vật dẫn để mở cánh cửa, triệu hoán hồn phách tám con Thái Cổ Lôi Long trưởng thành lao ra từ vòng xoáy. Thần thông này gần tiếp cận Đệ Tam Bộ đại năng.","theLucLienQuan":["thiem-loi-toc"],"nguon":["@c1270"]},{"id":"loi-vuc-thiem-loi-toc","name":"Lôi vực (Thiểm Lôi Tộc)","cn":"雷域","capDo":"vuc","parentId":"lanh-dia-thiem-loi-toc","blurb":"Vùng lôi vực bao quanh lãnh địa Thiểm Lôi Tộc, nơi bản thể Vương Lâm ẩn tu trong lôi cầu vạn trượng ở vị trí rất sâu.","detail":"Khu vực sấm sét cuồn cuộn bốn phía quanh thánh địa Thiểm Lôi Tộc. Vương Lâm dùng thân mình làm mồi dẫn đại trưởng lão vào lôi vực giao chiến. Bản thể Vương Lâm ngồi trong một lôi cầu vạn trượng ở vị trí rất sâu bên trong lôi vực; khi bản thể mở mắt, toàn bộ lôi vực sôi trào, lôi long đại trưởng lão run rẩy tan vỡ. Sau trận đại chiến Tụ Lôi Ấn, lôi vực bị sóng sấm sét mở rộng gấp trăm lần, lan ra khắp tinh không Thái Cổ Tinh Thần.","theLucLienQuan":["thiem-loi-toc"],"nguon":["@c1270"]},{"id":"mieu-tho-thanh-dia-thiem-loi-toc","name":"Miếu thờ thánh địa Thiểm Lôi tộc","capDo":"khac","parentId":"thanh-dia-thiem-loi-toc","blurb":"Nơi sấm sét bất diệt rút về sau khi bị trọng thương, được mười sáu tu chân tinh anh dùng đại trận phong tỏa bảo vệ.","detail":"Miếu thờ nằm trong thánh địa Thiểm Lôi tộc, là nơi an trí thánh vật sấm sét bất diệt. Sau trận chiến với trường kiếm bảy thước, sấm sét bất diệt bị trọng thương rút về đây. Mười sáu tu chân tinh anh Thiểm Lôi tộc mở đại trận khổng lồ phong tỏa, không cho ai xâm nhập.","theLucLienQuan":["Thiểm Lôi tộc"],"nguon":["@c1272"]},{"id":"muoi-sau-tu-chan-tinh-thiem-loi-toc","name":"Mười sáu tu chân tinh Thiểm Lôi tộc","cn":"","capDo":"tinh-cau","parentId":"thai-co-tinh-than","blurb":"Cụm mười sáu tu chân tinh là địa bàn trọng yếu của Thiểm Lôi tộc, được đại trận phòng hộ bao phủ. Đây là nơi Vương Lâm kéo lôi vực tới và dùng lôi long phá mở tầng phòng hộ.","detail":"Mười sáu tu chân tinh được bao bọc bởi thanh quang và tử quang của đại trận phòng hộ Thiểm Lôi tộc. Khi lôi long của Vương Lâm liên tục công kích, lớp phòng hộ bị nứt vỡ và mở ra lỗ hổng lớn, để lộ địa bàn Thiểm Lôi tộc trước mũi tiến công.","theLucLienQuan":["Thiểm Lôi tộc"],"nguon":["@c1274"]},{"id":"tinh-khong-thiem-loi-toc","name":"Tinh không Thiểm Lôi tộc","cn":"","capDo":"khac","parentId":"muoi-sau-tu-chan-tinh-thiem-loi-toc","blurb":"Tinh không Thiểm Lôi tộc là không gian nơi Vương Lâm triệu Côn Cực Tiên sau khi phá trận. Tại đây tàn thần đại trưởng lão Thiểm Lôi tộc bị phơi bày trước tộc nhân.","detail":"Sau khi lôi long xé mở đại trận phòng hộ, Vương Lâm tiến vào tinh không Thiểm Lôi tộc và triệu Côn Cực Tiên. Kim quang từ thân roi bùng lên, quấn tàn thần nguyên thần đã bị hủy hoại của đại trưởng lão Thiểm Lôi tộc.","theLucLienQuan":["Thiểm Lôi tộc"],"nguon":["@c1274"]},{"id":"sau-tu-chan-tinh","name":"Sáu tu chân tinh","cn":"","capDo":"tinh-cau","parentId":"tinh-khong-thiem-loi-toc","blurb":"Sáu tu chân tinh bao quanh thánh địa Thiểm Lôi Tộc. Chúng xác định vị trí trung tâm của thánh địa trong lần Vương Lâm quay lại công phá.","detail":"Thánh địa Thiểm Lôi Tộc nằm giữa sáu tu chân tinh, là khu vực Vương Lâm cưỡi lôi long lao tới sau khi làm toàn tộc rối loạn. Từ đây hắn đánh vào tầng phòng hộ và khiến miếu thờ chứa sấm sét bất diệt tan vỡ.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1275"]},{"id":"hu-vo-tinh-khong-vong-xoay-khong-lo","name":"Hư vô tinh không / vòng xoáy khổng lồ","cn":"","capDo":"khac","parentId":"thai-co-tinh-than","blurb":"Khu vực hư vô trong tinh không nơi vòng xoáy khổng lồ xuất hiện. Vòng xoáy này kéo sấm sét bất diệt vào trong và phát ra âm thanh uy hiếp Vương Lâm.","detail":"Sau khi sấm sét bất diệt thoát khỏi miếu thờ, trong hư vô tinh không xuất hiện một vòng xoáy khổng lồ có tia chớp xoay chuyển. Đây là nơi Vương Lâm bám lấy sấm sét và hóa thân Cổ Thần để tranh đoạt với chủ thể bí ẩn bên trong.","theLucLienQuan":[],"nguon":["@c1275"]},{"id":"lam-son","name":"Lam sơn","cn":"","capDo":"khac","parentId":"tam-ti-toc","blurb":"Lam sơn là địa điểm trong Tam Ti tộc. Lý Thiến Mai và Lam Mộng Đạo Tôn đang ở đây khi âm thanh từ vòng xoáy làm Thái Cổ Tinh Thần chấn động.","detail":"Tại Lam sơn, Lý Thiến Mai nhìn phương xa với vẻ mê man và vùng vẫy, còn Lam Mộng Đạo Tôn biến sắc trước dị động tinh không. Địa điểm này gắn với dấu hiệu ký ức của Lý Thiến Mai thức tỉnh trong chương 1275.","theLucLienQuan":["Tam Ti tộc"],"nguon":["@c1275"]},{"id":"vien-co-tien-phi","name":"Viễn Cổ Tiên Phi","cn":"","capDo":"khac","parentId":"thai-co-tinh-than","blurb":"Nơi dấu hiệu tái hiện trong chương 1276, khiến nhiều đại năng tại Thái Cổ Tinh Thần đồng loạt cảm ứng.","detail":"Dấu hiệu ở Viễn Cổ Tiên Phi xuất hiện một lần nữa, làm Lam Mộng Đạo Tôn, các đại năng Đệ Tam Bộ và vài nữ tử trong Viễn Cổ Tiên Vực cùng nhìn lên tinh không. Địa danh này gắn với biến động cấp cao trong Thái Cổ Tinh Thần.","theLucLienQuan":["Viễn Cổ Tiên Vực","Đệ Tam Bộ"],"nguon":["@c1276"]},{"id":"man-hoang-dia-trong-thai-co-tinh-than","name":"Man Hoang địa trong Thái Cổ Tinh Thần","cn":"","capDo":"khac","parentId":"thai-co-tinh-than","blurb":"Khu vực trong Thái Cổ Tinh Thần nơi Thác Sâm xuất hiện ở chương 1276. Tại đây hắn chống lại ý chí nô dịch và cảm nhận khí tức đồng tộc.","detail":"Man Hoang địa là nơi Thác Sâm lao đi, tự đánh mi tâm và gầm lên không chịu làm nô lệ. Sau đó hắn cảm nhận khí tức đồng tộc quen thuộc, liên hệ tới ký ức Đồ Ti.","theLucLienQuan":["Cổ Thần"],"nguon":["@c1276"]},{"id":"tinh-khong-chien-truong-cua-vuong-lam","name":"Tinh không chiến trường của Vương Lâm","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Khu vực tinh không nơi Vương Lâm tranh đoạt sấm sét bất diệt và giao chiến với cánh tay sứ giả thiên đạo.","detail":"Tại chiến trường tinh không này, vòng xoáy, sấm sét bất diệt và cánh tay sứ giả cùng xuất hiện. Một kiếm của Vương Lâm chém đứt bàn tay khổng lồ, dư chấn khiến thánh đại bên dưới tan vỡ và mười sáu tu chân tinh ở xa đổi quỹ tích.","theLucLienQuan":["Cổ Thần","Sứ giả thiên đạo"],"nguon":["@c1276"]},{"id":"do-thanh-huong-tay","name":"Đô thành hướng tây","cn":"","capDo":"thanh","parentId":null,"blurb":"Một đô thành phàm tục lớn ở hướng tây nơi Vương Lâm đi qua. Thành này dùng Phàn Tinh làm vật giao dịch thay ngân lượng.","detail":"Đô thành hướng tây có dân cư đông đúc và sinh hoạt phàm tục rõ nét. Tại đây, Vương Lâm tìm hiểu cơ chế dùng Phàn Tinh, dùng nguyên thần dò xuống lòng đất phát hiện mỏ Phàn Tinh, rồi tiếp tục đi tới khu thành tây để mua nhà tạm trú.","theLucLienQuan":[],"nguon":["@c1277"]},{"id":"thanh-tay","name":"Thành tây","cn":"","capDo":"khac","parentId":"do-thanh-huong-tay","blurb":"Khu dân cư nghèo và đông đúc trong đô thành hướng tây. Vương Lâm mua một căn nhà ở đây để tạm sống như học trò chờ thi.","detail":"Thành tây có nhà cửa chen chúc, đường sá xấu, nhiều căn chưa tu sửa và hầu như đều treo xâu lá dưới mái hiên. Khu vực này tạo nên bối cảnh đời phàm yên bình với hàng xóm, tiếng trẻ con, khói bếp, quán rượu gạo và tiếng gõ mõ cầm canh.","theLucLienQuan":[],"nguon":["@c1277"]},{"id":"can-nha-cua-vuong-lam-o-thanh-tay","name":"Căn nhà của Vương Lâm ở thành tây","cn":"","capDo":"khac","parentId":"thanh-tay","blurb":"Căn nhà đơn sơ nhưng sạch sẽ mà Vương Lâm mua tại thành tây. Đây là nơi hắn vừa nhập vai học trò phàm tục vừa âm thầm luyện hóa tám Thái Cổ Lôi Long.","detail":"Căn nhà nằm trong khu dân cư nghèo, đủ đơn sơ để Vương Lâm hòa vào đời phàm. Ban đêm, bên ngoài căn nhà yên tĩnh như thường, nhưng bên trong nguyên thần Vương Lâm lại diễn ra quá trình biển lửa lam sắc luyện hóa và thôn phệ Thái Cổ Lôi Long.","theLucLienQuan":[],"nguon":["@c1277"]},{"id":"thanh-tri-noi-vuong-lam-tru-lai","name":"Thành trì nơi Vương Lâm trú lại","cn":"","capDo":"thanh","parentId":null,"blurb":"Thành trì nơi Vương Lâm trú lại là một thành phàm nhân đang chìm trong mưa lớn. Từ nơi này, hắn nghe tin Trường Tôn Hội phát lệnh truy sát rồi luyện hóa lôi long và dung hợp sấm sét bất diệt.","detail":"Trong cơn mưa tầm tã, thành trì có trẻ con chơi mưa, người đi đường mặc áo tơi và cảnh sinh hoạt phàm nhân khiến Vương Lâm nhớ lại tuổi thơ trên Chu Tước tinh. Đây cũng là nơi hắn tạm ở để nghe ngóng tin tức, luyện hóa Thái Cổ Lôi Long cuối cùng và bắt đầu dung hợp sấm sét bất diệt.","theLucLienQuan":[],"nguon":["@c1278"]},{"id":"tang-may-tren-tu-chan-tinh","name":"Tầng mây trên tu chân tinh","cn":"","capDo":"khac","parentId":null,"blurb":"Tầng mây trên tu chân tinh là nơi Nguyệt Huyên, thanh niên họ Dự và thanh niên họ Chu gặp nhau. Tại đây tin Thiểm Lôi Tộc bị diệt và Thái Cổ Tinh Thần Lệnh được truyền ra.","detail":"Trên tầng mây, thanh niên họ Dự cùng Nguyệt Huyên đang đi theo lệnh triệu tập thì gặp thanh niên họ Chu xuất hiện từ gió đen. Cuộc gặp này hé lộ việc Trường Tôn Hội ban lệnh truy sát hung thủ diệt Thiểm Lôi Tộc.","theLucLienQuan":["Trường Tôn Hội","Thiểm Lôi Tộc"],"nguon":["@c1278"]},{"id":"hoang-thanh-phia-dong","name":"Hoàng thành phía đông","cn":"","capDo":"thanh","parentId":null,"blurb":"Hoàng thành phía đông là nơi có căn lầu cao nhất, các lão giả đạo bào tụ lại quan sát sấm mưa dị thường. Họ dùng thần thức dò xét nhưng không phát hiện manh mối.","detail":"Khi nguyên thần lôi đình của Vương Lâm thành hình làm cả tu chân tinh sấm động, các lão giả tu vi Tịnh Niết và Toái Niết trong căn lầu cao nhất hoàng thành phía đông sinh nghi. Họ liên hệ dị tượng với biến cố Thiểm Lôi Tộc nhưng vẫn không tìm ra dấu vết.","theLucLienQuan":[],"nguon":["@c1278"]},{"id":"son-mon-chan-ngon-toc","name":"Sơn môn Chân Ngôn Tộc","cn":"","capDo":"khac","parentId":null,"blurb":"Sơn môn Chân Ngôn Tộc nằm trong dãy núi phía đông của tu chân tinh. Trên đỉnh núi cao tại đây, lão nhân tóc trắng cảm nhận điềm đại nạn trong mưa sấm.","detail":"Sơn môn của Chân Ngôn Tộc nằm ở dãy núi kéo dài phía đông, có một đỉnh núi cao ngập trời. Khi mưa sấm dị thường bao phủ, lão nhân tóc trắng trong tộc đứng trên đỉnh núi nhìn xa và cảm thấy đại nạn sắp đến.","theLucLienQuan":["Chân Ngôn Tộc"],"nguon":["@c1278"]},{"id":"tu-chan-tinh-vuong-lam-dang-o","name":"Tu chân tinh Vương Lâm đang ở","cn":"","capDo":"tinh-cau","parentId":"thai-co-tinh-than","blurb":"Tu chân tinh nơi Vương Lâm ẩn thân trong thành tây khi cuộc lùng sục diễn ra. Các địa phương trên tinh cầu này đều xuất hiện tình cảnh dò xét tương tự.","detail":"Trong chương 1279, cuộc tìm kiếm không chỉ diễn ra tại thành tây mà còn lan khắp tu chân tinh nơi Vương Lâm đang ở. Đây là một điểm trong mạng lùng sục rộng lớn do Thái Cổ Tinh Thần phát động.","theLucLienQuan":["Thái Cổ Tinh Thần"],"nguon":["@c1279"]},{"id":"mieu-tho-thiem-loi-toc","name":"Miếu thờ Thiểm Lôi Tộc","cn":"","capDo":"khac","parentId":"thiem-loi-toc","blurb":"Địa điểm xuất hiện trong hình ảnh ký ức thứ ba của sấm sét bất diệt. Tại đây từng có một luồng sấm sét bất diệt và tám tu sĩ đứng quanh.","detail":"Trong ký ức mà Vương Lâm nhìn thấy sau khi luyện hóa sấm sét bất diệt, miếu thờ Thiểm Lôi Tộc là nơi luồng sấm sét tồn tại từ lâu. Bên ngoài sấm sét có lão già Thiểm Lôi Tộc, bảy người khác và một thủ lĩnh có kim quang khiến Vương Lâm chấn động khi nhận ra.","theLucLienQuan":["Thiểm Lôi Tộc"],"nguon":["@c1279"]},{"id":"ngu-hanh-tinh","name":"Ngũ Hành tinh","cn":"","capDo":"tinh-cau","parentId":"chu-tuoc-tinh","blurb":"Địa điểm trong ký ức của Vương Lâm gắn với Nạp Đa và Cực Cảnh năm màu.","detail":"Vương Lâm nhớ lại từng thấy Cực Cảnh năm màu của Nạp Đa trên Ngũ Hành tinh tại Chu Tước tinh, từ đó liên hệ với ánh sáng năm màu trong mắt trái nam tu sĩ lạ.","theLucLienQuan":[],"nguon":["@c1280"]},{"id":"tinh-vuc-dang-bi-luc-soat","name":"Tinh vực đang bị lục soát","cn":"","capDo":"vuc","parentId":"thai-co-tinh-than","blurb":"Tinh vực nơi Vân Lạc tính ra mục tiêu đang ẩn hiện và nhóm truy tìm đang kiểm tra các tu chân tinh.","detail":"Lão già đạo bào cùng bảy người đàn ông trung niên kiểm tra các tu chân tinh trong khu vực này để tìm hung thủ hủy diệt Thiểm Lôi tộc. Ký ức nguyên thần của lão giúp Vương Lâm nắm được bố trí truy tìm trong tinh vực.","theLucLienQuan":["Thái Cổ Tinh Thần","Trường Tôn Hội"],"nguon":["@c1280"]},{"id":"thap-van-dai-son","name":"Thập Vạn đại sơn","cn":"","capDo":"vuc","parentId":"tu-chan-tinh-vuong-lam-dang-o","blurb":"Thập Vạn đại sơn là vùng núi hiểm trở ở cực nam tu chân tinh. Vương Lâm chuyển tới một sơn cốc sâu trong khu vực này để luyện hóa Lôi Lục đạo và ẩn tránh lục soát.","detail":"Sau khi Lôi Lục đạo bùng phát làm lộ lôi quang, Vương Lâm rời căn nhà và thuấn di tới Thập Vạn đại sơn. Về sau, nơi này cũng bị các tu sĩ lục soát từng tấc đất nhưng không phát hiện dấu vết hắn.","theLucLienQuan":["Chân Ngôn Tộc","Trường Tôn Hội"],"nguon":["@c1281"]},{"id":"vung-tinh-vuc-suong-mu-trong-thai-co-tinh-than","name":"Vùng tinh vực sương mù trong Thái Cổ tinh thần","cn":"","capDo":"vuc","parentId":"thai-co-tinh-than","blurb":"Vùng tinh vực sương mù nằm sâu trong Thái Cổ tinh thần, thuộc địa phương của nhiều đại tộc. Tu chân tinh màu xanh nơi Vân Lạc suy tính vị trí Vương Lâm nằm tại khu vực này.","detail":"Khu vực này được miêu tả có sương mù bao phủ và là địa phương của nhiều đại tộc. Từ đây, Vân Lạc dùng quả cầu nước xác định nơi người hủy diệt Thiểm Lôi tộc đang trú ngụ.","theLucLienQuan":["Trường Tôn Hội"],"nguon":["@c1281"]},{"id":"tu-chan-tinh-mau-xanh-cua-van-lac","name":"Tu chân tinh màu xanh của Vân Lạc","cn":"","capDo":"tinh-cau","parentId":"vung-tinh-vuc-suong-mu-trong-thai-co-tinh-than","blurb":"Tu chân tinh màu xanh có hồ nước như gương, đảo nhỏ, lầu các và hoa cỏ. Đây là nơi Vân Lạc dùng quả cầu nước suy tính ra vị trí Vương Lâm.","detail":"Trên đảo nhỏ của tinh cầu này, Vân Lạc đứng trước quả cầu nước, hiển hiện hình bóng Vương Lâm và tu chân tinh mục tiêu. Sau đó nàng truyền tin cho Trường Tôn Hội cùng các trưởng lão.","theLucLienQuan":["Trường Tôn Hội"],"nguon":["@c1281"]},{"id":"khe-nut-hu-vo-trong-tinh-khong-thai-co-tinh-than","name":"Khe nứt hư vô trong tinh không Thái Cổ tinh thần","cn":"","capDo":"khac","parentId":"thai-co-tinh-than","blurb":"Khe nứt hư vô là nơi tối lạnh trong tinh không Thái Cổ tinh thần. Tư Mặc Tử bế quan tại đây để hấp thu Lục Phẩm đạo linh.","detail":"Trong khe nứt có khí lạnh và nguy hiểm cho sinh linh. Tư Mặc Tử ở đây hấp thu đạo linh, nhận huyết chỉ của Trường Tôn Hội rồi phóng hư ảnh Thiên Nhân Đệ Ngũ Suy ra ngoài làm nhiệm vụ.","theLucLienQuan":["Trường Tôn Hội","Đệ Tam Bộ"],"nguon":["@c1281"]},{"id":"khong-mon","name":"Không Môn","cn":"","aliases":["Cánh cửa Không Chi","Thiên Địa đại môn"],"capDo":"khac","parentId":null,"blurb":"Cánh cửa khổng lồ ngăn cách việc tiến lên Đệ Tam Bộ, hiện ra trên bầu trời khi Vương Lâm thử phá vách ngăn.","detail":"Không Môn bị lôi bản nguyên đại thành và lôi đồ của Vương Lâm công kích dữ dội. Cánh cửa xuất hiện một khe nứt nhỏ rồi chậm rãi tiêu tán, khiến Vương Lâm nhìn thấy hy vọng nhưng cũng nhận ra một luồng bản nguyên đại thành chưa đủ để phá vỡ vách ngăn Đệ Tam Bộ.","theLucLienQuan":[],"tabs":{"tienTrinh":[{"chuong":"@c1283","loai":"nhắc tới","importance":"major","giaiDoan":"Bị lôi bản nguyên đánh nứt","text":"Không Môn bị Vương Lâm dùng lôi bản nguyên đại thành và lôi đồ công kích, xuất hiện một khe nứt nhỏ rồi tiêu tán.","anchor":"tuy rất nhỏ nhưng đây vẫn là một khe nứt."}]},"capNhatToi":"@c1283","nguon":["@c1283"]},{"id":"tinh-vuc-phieu-mieu-toc","name":"Tinh vực Phiêu Miễu tộc","cn":"","capDo":"vuc","parentId":"thai-co-tinh-than","blurb":"Tinh vực của Phiêu Miễu tộc, nơi có hòn đảo cô gái hắc y từng tính vị trí Vương Lâm. Dị tượng Không Môn trong chương này khiến hoa cỏ héo, hồ nước cuộn xoáy và sấm sét giáng xuống.","detail":"Tinh vực Phiêu Miễu tộc là nơi chuyển cảnh sau Lam Sơn. Trên hòn đảo trong tinh vực này, cô gái hắc y đang thổ nạp thì dị tượng liên quan đến Không Môn của Vương Lâm xuất hiện, khiến ba quẻ tổ tiên truyền lại ứng nghiệm.","theLucLienQuan":["Phiêu Miễu tộc"],"nguon":["@c1284"]},{"id":"dien-lac-dia","name":"Điên Lạc Địa","cn":"","capDo":"vuc","parentId":"thai-co-tinh-than","blurb":"Vùng tinh vực hỗn loạn do ba trăm bảy mươi hai bộ tộc nhỏ tạo thành. Đây là nơi Vương Lâm chọn để ẩn náu và chữa thương sau biến cố Không Môn.","detail":"Điên Lạc Địa có nhiều tu chân tinh, giao dịch nguyên tinh, pháp bảo, đan dược và công pháp, đồng thời che chở phản đồ cùng người bị truy sát. Nơi này từng khiến đại tộc, Cửu Thiên Ma Tôn và Trường Tôn Hội phải kiêng kỵ, nên Vương Lâm dựa vào ký ức truyền thừa để chọn làm nơi tạm lánh.","theLucLienQuan":["Điên Lạc Địa","Trường Tôn Hội"],"nguon":["@c1284"]},{"id":"tu-chan-tinh-khong-co-linh-khi-trong-dien-lac-dia","name":"Tu chân tinh không có linh khí trong Điên Lạc Địa","cn":"","capDo":"tinh-cau","parentId":"dien-lac-dia","blurb":"Tu chân tinh trong Điên Lạc Địa nơi Vương Lâm thuê động phủ để chữa thương. Nơi này không có linh khí, nhưng có động phủ được đổi bằng đan dược trong thời hạn trăm năm.","detail":"Sau khi vào Điên Lạc Địa, Vương Lâm chọn một tu chân tinh không có linh khí, lấy đan dược đổi quyền sử dụng một động phủ. Đây là điểm dừng chân đầu tiên của hắn trong vùng đất hỗn loạn này.","theLucLienQuan":["Điên Lạc Địa"],"nguon":["@c1284"]},{"id":"dong-phu-cua-vuong-lam-o-dien-lac-dia","name":"Động phủ của Vương Lâm ở Điên Lạc Địa","cn":"","capDo":"khac","parentId":"tu-chan-tinh-khong-co-linh-khi-trong-dien-lac-dia","blurb":"Động phủ chiếm gần nửa ngọn núi, được Vương Lâm đổi bằng đan dược trong thời hạn trăm năm. Cuối chương, cửa động phủ mở ra và có người nhanh chóng bước vào.","detail":"Động phủ này là nơi Vương Lâm bế quan thổ nạp, nuốt đan dược chữa thương sau khi vào Điên Lạc Địa. Khi hắn đang định thần, cửa chính động phủ dần mở ra, tạo biến cố mới với một người chưa rõ danh tính bước vào.","theLucLienQuan":["Điên Lạc Địa"],"nguon":["@c1284"]},{"id":"son-coc-cua-lao-ho-chuong","name":"Sơn cốc của lão họ Chương","cn":"","capDo":"khac","parentId":"tu-chan-tinh-vuong-lam-dang-o","blurb":"Sơn cốc u tĩnh, hoang vu, âm khí tràn ngập, là nơi lão họ Chương đặt động phủ và tiếp Chung Đại Hồng.","detail":"Trong sơn cốc có thực vật nhọn hoắt, xương thú vung vãi như dao động theo trận pháp, bên trong còn có động phủ phủ sương đen. Chung Đại Hồng tới đây biếu đan dược cho lão họ Chương và nhờ lão dẫn đường đi mua con rối của Ám Hạt Tộc.","theLucLienQuan":[],"nguon":["@c1285"]},{"id":"thanh-tri-hoang-phe-phia-tay-tu-chan-tinh","name":"Thành trì hoang phế phía tây tu chân tinh","cn":"","capDo":"thanh","parentId":"tu-chan-tinh-vuong-lam-dang-o","blurb":"Thành trì hoang phế ở phía tây tu chân tinh, bị sa mạc bao quanh nhưng vẫn có nhiều tu sĩ qua lại.","detail":"Nơi này có gạch vỡ khắp nơi, bên trong đặt đại điện của Ám Hạt Tộc và là điểm giao dịch con rối. Sau khi Chung Đại Hồng bị đánh thương, Vương Lâm tới đây cho tu sĩ trong thành ba hơi thở rời đi rồi dẫn lôi đình phá tan toàn thành.","theLucLienQuan":["Ám Hạt Tộc"],"nguon":["@c1285"]},{"id":"dai-dien-am-hat-toc","name":"Đại điện Ám Hạt Tộc","cn":"","capDo":"khac","parentId":"thanh-tri-hoang-phe-phia-tay-tu-chan-tinh","blurb":"Đại điện ở trung tâm thành trì hoang phế, nơi Ám Hạt Tộc giao dịch con rối và đặt tượng bọ cạp đen.","detail":"Chung Đại Hồng cùng lão họ Chương vào đại điện này để đổi hồn đan lấy con rối Hóa Thần sơ kỳ. Chính giữa điện có pho tượng bọ cạp đen tỏa hàn khí mạnh khiến Chung Đại Hồng thổ huyết; về cuối chương, đại điện bị lôi đình của Vương Lâm đánh nổ.","theLucLienQuan":["Ám Hạt Tộc"],"nguon":["@c1285"]},{"id":"bao-thap-duoi-nen-dai-dien","name":"Bảo tháp dưới nền đại điện","cn":"","capDo":"khac","parentId":"dai-dien-am-hat-toc","blurb":"Không gian bảo tháp ẩn dưới nền đại điện Ám Hạt Tộc, nơi có nhiều tầng cho tu sĩ Ám Hạt Tộc thổ nạp.","detail":"Thiếu chủ Ám Hạt Tộc ở tầng hai bảo tháp, trước một pho tượng bọ cạp, và tại đây hắn ra lệnh bắt một người, đánh thương một người sau giao dịch hồn đan. Khi Vương Lâm phá thành bằng lôi đình, bảo tháp dưới đất lộ ra một nửa rồi nứt vỡ sụp đổ.","theLucLienQuan":["Ám Hạt Tộc"],"nguon":["@c1285"]},{"id":"chu-tuoc-thanh-tong-trong-lien-minh-tinh-vuc","name":"Chu Tước Thánh Tông trong Liên Minh Tinh Vực","cn":"","capDo":"khac","parentId":"lien-minh-tinh-vuc","blurb":"Chu Tước Thánh Tông trong Liên Minh Tinh Vực là nơi có hòn đá trắng lớn từng gắn với Chu Tước lão Thánh Hoàng. Vương Lâm dùng ký ức về nơi này để đối chiếu với Viêm hỏa dị tinh ở Điên Lạc.","detail":"Nơi này được nhắc qua mảnh tinh không bị thiêu đốt và hòn đá trắng mà Chu Tước lão Thánh Hoàng từng ngồi. Sự tương đồng với Viêm hỏa dị tinh khiến Vương Lâm nghi Điên Lạc có liên hệ với Chu Tước Thánh Tông.","theLucLienQuan":["Chu Tước Thánh Tông"],"nguon":["@c1287"]},{"id":"manh-tinh-khong-bi-thieu-dot","name":"Mảnh tinh không bị thiêu đốt","cn":"","capDo":"khac","parentId":"chu-tuoc-thanh-tong-trong-lien-minh-tinh-vuc","blurb":"Mảnh tinh không bị thiêu đốt là vùng sâu trong Chu Tước Thánh Tông, nơi lơ lửng hòn đá trắng liên quan tới Chu Tước lão Thánh Hoàng. Nó được Vương Lâm nhớ lại khi thấy Viêm hỏa dị tinh.","detail":"Hình ảnh hòn đá trắng trong mảnh tinh không này trở thành căn cứ để Vương Lâm nhận ra Viêm hỏa dị tinh ở Điên Lạc có hình dạng giống hệt.","theLucLienQuan":["Chu Tước Thánh Tông"],"nguon":["@c1287"]},{"id":"tu-chan-tinh-cua-truong-lao-lac-sinh-hoi-gan-nhat","name":"Tu chân tinh của trưởng lão Lạc Sinh hội gần nhất","cn":"","capDo":"tinh-cau","parentId":"dien-lac-dia","blurb":"Tu chân tinh của trưởng lão Lạc Sinh hội gần nhất là điểm đến kế tiếp mà Vương Lâm yêu cầu Kiệt trưởng lão dẫn đường. Nơi này chưa được miêu tả trực tiếp trong chương nhưng đã trở thành mục tiêu di chuyển mới.","detail":"Sau khi rời động phủ, Vương Lâm gọi Kiệt trưởng lão và yêu cầu dẫn tới tu chân tinh gần nhất nơi trưởng lão Lạc Sinh hội sinh sống.","theLucLienQuan":["Lạc Sinh hội"],"nguon":["@c1287"]},{"id":"khoang-tinh-khong-do-truong-ton-hoi-dieu-khien","name":"Khoảng tinh không do Trường Tôn hội điều khiển","cn":"","capDo":"vuc","parentId":"dien-lac-dia","blurb":"Khoảng tinh không do Trường Tôn hội điều khiển nằm phía trước Điên Lạc theo quan sát của Tư Mặc Tử. Đây là vùng được nhắc khi hắn xuất hiện ngoài Điên Lạc.","detail":"Tư Mặc Tử nhìn vào Điên Lạc và nhận biết phía trước là khoảng tinh không do Trường Tôn hội điều khiển, từ đó suy tính cách tiến vào truy tìm Vương Lâm.","theLucLienQuan":["Trường Tôn hội"],"nguon":["@c1287"]},{"id":"chu-tinh-long-giap-toc","name":"Chủ tinh Long Giáp Tộc","cn":"","capDo":"tinh-cau","parentId":"dien-lac-dia","blurb":"Tu chân tinh màu xanh nhiều sinh cơ của Long Giáp Tộc. Đây là chủ tinh có trưởng lão thứ chín Lạc Sinh hội tọa trấn, nơi Vương Lâm đến mua con rối và Viêm hỏa dị tinh.","detail":"Chủ tinh Long Giáp Tộc có sinh cơ và linh lực vượt xa tu chân tinh Ám Hạt Tộc. Chương 1288 đưa Vương Lâm, tộc trưởng Ám Hạt Tộc và Tư Mặc Tử tới cùng một khu vực này, khiến nơi đây trở thành điểm giao giữa việc mua dị tinh, con rối và nguy cơ giao chiến với tu sĩ bước thứ ba.","theLucLienQuan":["Long Giáp Tộc","Lạc Sinh hội","Ám Hạt Tộc","Hỏa Tước tộc"],"nguon":["@c1288"]},{"id":"tu-chan-tinh-am-hat-toc","name":"Tu chân tinh Ám Hạt Tộc","cn":"","capDo":"tinh-cau","parentId":"dien-lac-dia","blurb":"Tu chân tinh của Ám Hạt Tộc trong vùng đất Điên Lạc. Đây là điểm xuất phát của Vương Lâm và tộc trưởng Ám Hạt Tộc trước khi tới Long Giáp Tộc.","detail":"Sau biến cố ở Ám Hạt Tộc, Vương Lâm được tộc trưởng Ám Hạt Tộc dẫn rời khỏi tu chân tinh này để đi tới chủ tinh Long Giáp Tộc, nơi có phường thị bán con rối và Viêm hỏa dị tinh.","theLucLienQuan":["Ám Hạt Tộc"],"nguon":["@c1288"]},{"id":"phuong-thi-phia-dong-long-giap-toc","name":"Phường thị phía đông của Long Giáp Tộc","cn":"","capDo":"thanh","parentId":"chu-tinh-long-giap-toc","blurb":"Khu phường thị ở thành phía đông trên chủ tinh Long Giáp Tộc. Đây là nơi có cửa hàng Long Giáp Tộc bán con rối và Viêm hỏa dị tinh.","detail":"Tộc trưởng Ám Hạt Tộc dẫn Vương Lâm tới phường thị phía đông của Long Giáp Tộc sau khi vào chủ tinh. Khu vực này là điểm giao dịch khiến Vương Lâm gặp nữ tử quản sự và lão giả Hỏa Tước tộc tranh mua Viêm hỏa dị tinh.","theLucLienQuan":["Long Giáp Tộc","Hỏa Tước tộc"],"nguon":["@c1288"]},{"id":"lau-cac-cua-hang-long-giap-toc","name":"Lầu các cửa hàng Long Giáp Tộc","cn":"","capDo":"khac","parentId":"phuong-thi-phia-dong-long-giap-toc","blurb":"Cửa hàng cổ kính trong phường thị phía đông của Long Giáp Tộc. Nữ tử quản sự tiếp Vương Lâm ở lầu hai, nơi lão giả Hỏa Tước tộc xuất hiện tranh mua Viêm hỏa dị tinh.","detail":"Lầu các cửa hàng Long Giáp Tộc là nơi Vương Lâm trực tiếp nêu yêu cầu mua Viêm hỏa dị tinh. Tại đây, tộc trưởng Ám Hạt Tộc đứng sau hắn không dám ngồi, khiến nữ tử quản sự kinh ngạc, rồi lão giả Hỏa Tước tộc bước lên lầu hai đòi mua cùng vật phẩm.","theLucLienQuan":["Long Giáp Tộc","Hỏa Tước tộc","Ám Hạt Tộc"],"nguon":["@c1288"]},{"id":"tu-chan-tinh-long-giap-toc","name":"Tu chân tinh của Long Giáp Tộc","cn":"","capDo":"tinh-cau","parentId":"dien-lac-dia","blurb":"Tinh cầu thuộc địa bàn Long Giáp Tộc tại vùng đất Điên Lạc, nơi Vương Lâm giao dịch, luyện hóa pháp bảo và công khai khiêu chiến Tư Mặc Tử.","detail":"Trên tu chân tinh này, Vương Lâm đi vào lầu các giao dịch của Long Giáp Tộc, đổi Viêm hỏa dị tinh và Băng long đan, sau đó lên đỉnh núi luyện lại một vạn Băng long đan, luyện Viêm hỏa dị tinh và thử mở phong ấn đoạn kiếm lộc cốt. Cuối chương, tiếng thách chiến của hắn vang khắp tinh cầu, khiến toàn bộ tu sĩ đều nghe rõ.","theLucLienQuan":["Long Giáp Tộc","Hỏa Tước tộc","Ám Hạt Tộc"],"nguon":["@c1289"]},{"id":"thanh-tri-phia-dong-tu-chan-tinh-long-giap-toc","name":"Thành trì phía đông của tu chân tinh","cn":"","capDo":"thanh","parentId":"tu-chan-tinh-long-giap-toc","blurb":"Thành trì ở phía đông tu chân tinh Long Giáp Tộc, nơi lão giả Hỏa Tước tộc cùng bảy tộc nhân nghiên cứu hồn đan.","detail":"Sau khi đổi được một trăm hồn đan từ Vương Lâm, lão giả Hỏa Tước tộc trở về thành trì phía đông của tu chân tinh này. Tại đây, hắn cùng bảy tộc nhân dùng lửa luyện tan hồn đan, cuối cùng phát hiện một giọt máu đỏ đậm là nguồn phát ra khí tức bổn nguyên trong đan.","theLucLienQuan":["Hỏa Tước tộc"],"nguon":["@c1289"]},{"id":"thanh-dia-long-giap-toc","name":"Thánh địa của Long Giáp Tộc","cn":"","capDo":"khac","parentId":"tu-chan-tinh-long-giap-toc","blurb":"Thánh địa riêng của Long Giáp Tộc, nơi tộc trưởng Long Giáp Tộc bàn mưu với Tư Mặc Tử.","detail":"Trong một lầu các tại thánh địa Long Giáp Tộc, tộc trưởng Long Giáp Tộc tiếp Tư Mặc Tử và nghe thiếu tộc trưởng báo đã xuất ra một vạn Băng long đan. Tộc trưởng sau đó đổi giao dịch thành cái cớ Vương Lâm cướp đan, dùng lý do này mời Tư Mặc Tử hỗ trợ bắt giết hắn.","theLucLienQuan":["Long Giáp Tộc"],"nguon":["@c1289"]},{"id":"dai-dien-long-giap-toc","name":"Đại điện Long Giáp Tộc","cn":"","capDo":"khac","parentId":"tu-chan-tinh-long-giap-toc","blurb":"Nơi Tư Mặc Tử rời đi sau khi phát hiện Vương Lâm trên đỉnh núi, và là nơi hai phụ tử Long Giáp Tộc bàn bạc nguy cơ.","detail":"Đại điện của Long Giáp Tộc là bối cảnh mở đầu chương: Tư Mặc Tử phát hiện Vương Lâm rồi lập tức rời đi để giao chiến. Sau đó trong điện chỉ còn tộc trưởng và thiếu tộc trưởng Long Giáp Tộc, hai người bàn về thân phận Vương Lâm, biến cố Thiểm Lôi tộc, Trường Tôn hội và quyết định đặt cược vào Tư Mặc Tử.","theLucLienQuan":["Long Giáp Tộc","Lạc Sinh hội"],"nguon":["@c1290"]},{"id":"tu-chan-tinh-cua-chan-ngon-toc","name":"Tu chân tinh của Chân Ngôn tộc","cn":"","capDo":"tinh-cau","parentId":"tinh-khong","blurb":"Tu chân tinh gắn với Chân Ngôn tộc, được Tư Mặc Tử nhớ lại trong lúc đánh giá thuật lôi đình của Vương Lâm. Màn giao chiến trước đó tại đây khiến hắn kiêng kỵ sức phá hoại của lôi đình.","detail":"Trong trận chiến năm nhịp thở, Tư Mặc Tử nhớ tới một màn trên Chân Ngôn tộc gần đó khi Vương Lâm thi triển lôi đình. Ký ức này trở thành lý do hắn nghiêm trọng đối đãi với lôi đồ vạn trượng.","theLucLienQuan":["Chân Ngôn Tộc"],"nguon":["@c1292"]},{"id":"thien-dia-chien-truong","name":"Thiên địa chiến trường","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Không gian giao chiến giữa Vương Lâm và Tư Mặc Tử trong giới hạn năm nhịp thở. Nơi này bị Thiên hoang địa lão và Tuế Nguyệt cấm làm suy hoại, rồi bị lôi đình và các vụ nổ hủy diệt khuấy động.","detail":"Chiến trường chịu ảnh hưởng trực tiếp từ thần thông của Tư Mặc Tử, khiến bầu trời khô vàng, mặt đất già nua và sụp đổ. Sau đó lôi đồ, vụ nổ đan dược màu vàng và Viêm hỏa dị tinh liên tiếp bộc phát trong cùng không gian này.","theLucLienQuan":[],"nguon":["@c1292"]},{"id":"dien-lac-tinh-vuc","name":"Điên Lạc tinh vực","cn":"","aliases":[],"capDo":"vuc","parentId":"thai-co-tinh-than","blurb":"Tinh vực thuộc phạm vi Điên Lạc, nơi các biến cố liên quan Vương Lâm, Long Giáp Tộc và Tham Lang cùng diễn ra trong chương này.","detail":"Điên Lạc tinh vực là khu vực bao trùm hành động của Vương Lâm sau khi được phong thiếu đế và tuyến Tham Lang tìm thi thể bọ cạp vạn cổ. Cuối chương, đoàn gần một ngàn tu sĩ hộ tống Tham Lang hoạt động trong tinh vực này để hướng tới tu chân tinh Ám Hạt Tộc.","theLucLienQuan":["Điên Lạc Địa","Long Giáp Tộc","Ám Hạt Tộc"],"nguon":["@c1294"]},{"id":"cai-khe-lon-trong-tinh-khong","name":"Cái khe lớn trong tinh không","cn":"","aliases":[],"capDo":"khac","parentId":"thai-co-tinh-than","blurb":"Nơi bổn tôn Tư Mặc Tử đả tọa ngoài tinh vực Điên Lạc. Tại đây hắn cảm ứng phân thân tử vong và triệu Thất Thải Thần Không Đinh.","detail":"Cái khe lớn trong tinh không là không gian Tư Mặc Tử ngồi khi phân thân của hắn chết. Hắn mở mắt, nổi sát khí, nhận định kế hoạch tế luyện thân thể bước thứ ba bị phá hỏng rồi gọi ra hai mươi chín cây Thất Thải Thần Không Đinh.","theLucLienQuan":["Trường Tôn hội"],"nguon":["@c1294"]},{"id":"tinh-khong-phia-truoc-tham-lang","name":"Tinh không phía trước Tham Lang","cn":"","capDo":"khac","parentId":"dien-lac-dia","blurb":"Khu vực tinh không nhiều lần xuất hiện gợn sóng không gian báo hiệu Vương Lâm sắp hiện thân trong cuộc truy đuổi Tham Lang.","detail":"Tham Lang liên tục phát hiện gợn sóng phía trước và dùng Cổ Tức Diệp thi triển Nhất diệp phong thiên để phong tỏa, khiến Vương Lâm phải đổi hướng truy kích.","theLucLienQuan":["Điên Lạc Địa"],"nguon":["@c1298"]},{"id":"co-mo-khu-mo-trong-dong-xoay","name":"Cổ mộ / khu mộ trong dòng xoáy","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian dị thường mà Tham Lang lọt vào qua dòng xoáy bên rìa La Thiên Tinh Vực.","detail":"Bên trong có cự thạch trôi nổi, không gian loạn lưu, sương mù sâu, tử khí, các đầu lâu khổng lồ có tinh điểm ở mi tâm, pháp bảo đặt trước đầu lâu, khu rừng khô héo vô biên và pho tượng bí ẩn mà Tham Lang lấy được.","theLucLienQuan":[],"nguon":["@c1300"]},{"id":"ben-ria-la-thien-tinh-vuc","name":"Bên rìa La Thiên Tinh Vực","cn":"","capDo":"khac","parentId":"la-thien-tinh-vuc","blurb":"Khu vực sát rìa La Thiên Tinh Vực nơi Tham Lang gặp dòng xoáy kỳ dị.","detail":"Tại đây, trong lúc Tham Lang tìm cách giải quyết mùi thối trên người, một dòng xoáy đột ngột xuất hiện trước mặt hắn, chỉ tồn tại chưa đầy ba hơi thở và mở đường đưa hắn vào cổ mộ.","theLucLienQuan":[],"nguon":["@c1300"]},{"id":"khu-rung-ram-kho-heo","name":"Khu rừng rậm khô héo","cn":"","capDo":"khac","parentId":"co-mo-khu-mo-trong-dong-xoay","blurb":"Vùng rừng vô biên trong cổ mộ, cây cối đều khô héo và không còn lá.","detail":"Tham Lang tỉnh lại tại khu rừng này sau khi bị gió lốc đánh trọng thương. Trong rừng có một cây đại thụ duy nhất chưa hoàn toàn chết khô, nơi hắn lấy Vạn Cổ Mộc Linh và Cổ Tức Diệp; tại trung tâm rừng, hắn tìm thấy pho tượng bí ẩn và cảm thấy cả khu rừng có thể đã héo rũ vì pho tượng đó.","theLucLienQuan":[],"nguon":["@c1300"]},{"id":"ngoai-phong-gioi-dai-tran","name":"Ngoài Phong Giới Đại Trận","cn":"","capDo":"khac","parentId":"phong-gioi","blurb":"Khu vực bên ngoài Phong Giới Đại Trận, nơi Tham Lang bị đưa tới sau khi rời cổ mộ.","detail":"Khi Tham Lang chạm vào pho tượng trong khu rừng khô héo, một dòng xoáy giống lúc vào cổ mộ xuất hiện. Hắn nhảy vào đó và đi tới một tinh vực xa lạ, về sau mới biết nơi này nằm ngoài Phong Giới Đại Trận.","theLucLienQuan":[],"nguon":["@c1300"]},{"id":"tinh-vuc-lao-hac-tinh","name":"Tinh vực Lạo Hắc tinh","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực nằm ngoài vùng đất Điên Lạc, nơi ba tộc nhân Hỏa Tước tộc bay qua khi mang máu trong đan dược về tộc.","detail":"Ba tộc nhân Hỏa Tước tộc xuất hiện tại tinh vực Lạo Hắc tinh trên đường rời vùng đất Điên Lạc để đưa máu trong đan dược về tộc nghiên cứu.","theLucLienQuan":["Hỏa Tước tộc"],"nguon":["@c1301"]},{"id":"la-thien-tinh-vuc-gan-hang-rao-gioi-noi","name":"La Thiên Tinh Vực gần hàng rào giới nội","cn":"","capDo":"vuc","parentId":"la-thien-tinh-vuc","blurb":"Khu vực gần hàng rào giới nội trong La Thiên Tinh Vực, nơi ký ức Tham Lang cho biết từng có dòng xoáy xuất hiện.","detail":"Vương Lâm tra ký ức Tham Lang và biết đây là một trong hai tọa độ quan trọng. Điểm này được hắn đánh giá là hữu dụng cho hành động về sau.","theLucLienQuan":["La Thiên Tinh Vực"],"nguon":["@c1302"]},{"id":"khe-lon-tren-bau-troi","name":"Khe lớn trên bầu trời","cn":"","capDo":"khac","parentId":"tu-chan-tinh-am-hat-toc","blurb":"Vết rách trên bầu trời xuất hiện khi ngân y nữ tử đánh ra chưởng ấn thanh khí, khác với khe không gian thông thường.","detail":"Khi lực lượng thanh khí bộc phát, bầu trời tu chân tinh tối sầm rồi bị xé ra một khe lớn. Từ khe này có thanh khí lao xuống nhập vào tay ngân y nữ tử, khiến nó như nối tới một tầng không gian kỳ dị sâu dưới tinh vực hơn là một khe không gian bình thường.","theLucLienQuan":[],"nguon":["@c1303"]},{"id":"thuc-hai-cua-ngan-y-nu-tu","name":"Thức hải của ngân y nữ tử","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian ý thức vẩn đục của ngân y nữ tử, nơi Vương Lâm thi triển Sưu thần thuật và gặp thanh quang phong tỏa.","detail":"Bên trong thức hải của ngân y nữ tử có sương mù xanh và ánh sáng xanh ngăn cản thần thức Vương Lâm. Ở nơi sâu nhất, hắn nhìn thấy một thân ảnh trung niên áo bảy màu ngồi đả tọa, không phải nguyên thần hay thực thể mà do một đạo phong ấn biến thành.","theLucLienQuan":[],"nguon":["@c1303"]},{"id":"dong-phu-cua-vuong-lam-tai-am-hat-toc","name":"Động phủ của Vương Lâm tại Ám Hạt Tộc","cn":"","aliases":[],"capDo":"khac","parentId":"am-hat-toc","blurb":"Nơi Vương Lâm bế quan tại Ám Hạt Tộc. Tại đây hắn luyện hóa Ma Hồn bình, dùng Đạo thuật Dung và Huyết luyện để dung hợp hồn phách Cổ Ma.","detail":"Trong động phủ tại Ám Hạt Tộc, Vương Lâm bế quan hơn hai tháng và tiến hành luyện Ma Hồn bình. Hắn đối kháng ma hồn trong bình, dung hợp chúng thành kén rồi dùng máu có bổn nguyên lực cùng máu Cổ Thần để huyết luyện.","theLucLienQuan":["Ám Hạt Tộc"],"nguon":["@c1304"]},{"id":"vung-dat-dien-lac","name":"Vùng đất Điên Lạc","cn":"","aliases":[],"capDo":"vuc","parentId":"thai-co-tinh-than","blurb":"Khu vực xảy ra dị biến lam hỏa khiến hỏa tu toàn vùng chấn động. Đây cũng là nơi Hỏa Tước tộc được lệnh truy tìm nguồn gốc giọt máu Chu Tước có bổn nguyên.","detail":"Một tinh cầu hoang dã tại vùng đất Điên Lạc bộc phát lam hỏa trong nửa nén nhang, khiến hỏa lực trong thân các hỏa tu như bị gọi về. Sau khi giọt máu Chu Tước có bổn nguyên được đưa về Hỏa Tước tộc, lão tổ ra tộc mệnh không tiếc giá nào tới vùng đất này truy tìm nguồn gốc.","theLucLienQuan":["Hỏa Tước tộc","Lạc Sinh hội"],"nguon":["@c1304"]},{"id":"tinh-cau-hoang-da-o-vung-dat-dien-lac","name":"Tinh cầu hoang dã ở vùng đất Điên Lạc","cn":"","aliases":[],"capDo":"tinh-cau","parentId":"vung-dat-dien-lac","blurb":"Tinh cầu hoang dã nơi lam hỏa bộc phát rồi biến mất. Hỏa Tước tộc tới truy xét nhưng chỉ còn cảm nhận được tia bổn nguyên giống trong hồn đan.","detail":"Tinh cầu này bùng lên ngọn lửa màu lam trong nửa nén nhang, làm hỏa tu tại vùng đất Điên Lạc kinh hãi vì hỏa lực trong thân chấn động. Khi trưởng lão Hỏa Tước tộc dẫn người đến điều tra, họ không tìm được vật gì, chỉ cảm nhận được khí tức bổn nguyên tương tự hồn đan.","theLucLienQuan":["Hỏa Tước tộc"],"nguon":["@c1304"]},{"id":"chu-tinh-hoa-tuoc","name":"Chủ tinh Hỏa Tước","cn":"","aliases":[],"capDo":"tinh-cau","parentId":"thai-co-tinh-than","blurb":"Chủ tinh của Hỏa Tước tộc tại Thái Cổ Tinh Thần. Nơi đây có pho tượng Hỏa Tước, đại điện của tộc trưởng và thánh địa biển lửa trong lòng tinh cầu.","detail":"Chủ tinh Hỏa Tước là trung tâm của Hỏa Tước tộc. Ba tộc nhân từ Điên Lạc đưa vật lạ về đây; tộc trưởng xem xét giọt máu tại đại điện dưới pho tượng Hỏa Tước, rồi vào thánh địa sâu trong chủ tinh cầu kiến lão tổ.","theLucLienQuan":["Hỏa Tước tộc"],"nguon":["@c1304"]},{"id":"dai-dien-duoi-pho-tuong-hoa-tuoc","name":"Đại điện dưới pho tượng Hỏa Tước","cn":"","aliases":[],"capDo":"khac","parentId":"chu-tinh-hoa-tuoc","blurb":"Đại điện dưới pho tượng Hỏa Tước trên chủ tinh. Đây là nơi tộc trưởng Hỏa Tước tộc đả tọa và kiểm tra giọt máu đang thiêu đốt.","detail":"Đại điện nằm dưới pho tượng Hỏa Tước toàn thân bị lửa thiêu đốt trên chủ tinh Hỏa Tước. Tại đây tộc trưởng tiếp nhận vật do ba tộc nhân từ Điên Lạc hộ tống về và nhận ra giọt máu có bổn nguyên.","theLucLienQuan":["Hỏa Tước tộc"],"nguon":["@c1304"]},{"id":"thanh-dia-hoa-tuoc-toc-trong-chu-tinh","name":"Thánh địa Hỏa Tước tộc trong chủ tinh","cn":"","aliases":[],"capDo":"khac","parentId":"chu-tinh-hoa-tuoc","blurb":"Thánh địa sâu trong chủ tinh Hỏa Tước, là không gian biển lửa nơi lão tổ Hỏa Tước tộc tu luyện. Ngay cả tộc trưởng cũng không được tự tiện tiến vào nếu không được triệu kiến.","detail":"Thánh địa Hỏa Tước tộc nằm sâu trong chủ tinh, có biển lửa tím và một trận pháp mơ hồ tại trung tâm. Lão tổ Hỏa Tước tộc tu luyện tại đây, tiếp nhận giọt máu do tộc trưởng dâng lên và xác nhận đó là máu Chu Tước có bổn nguyên.","theLucLienQuan":["Hỏa Tước tộc"],"nguon":["@c1304"]},{"id":"tu-chan-tinh-cua-am-hat-toc","name":"Tu chân tinh của Ám Hạt Tộc","cn":"","capDo":"tinh-cau","parentId":"thai-co-tinh-than","blurb":"Tinh cầu nơi Vương Lâm bế quan trong lãnh địa Ám Hạt Tộc. Chương 1305 ghi nhận toàn bộ ma khí quanh tinh cầu bị hút vào động phủ của hắn.","detail":"Tu chân tinh của Ám Hạt Tộc vốn bị ma khí bao quanh, nhưng khi còn sáu ngày tới tuyển chọn trưởng lão Lạc Sinh hội, ma vụ đột ngột co rút thành dòng xoáy và lao vào động phủ Vương Lâm. Nơi đây cũng chứng kiến Vụ Ma Thương hóa hắc mãng sau khi dung nạp ma hồn.","theLucLienQuan":["Ám Hạt Tộc","Vân Độn tộc","Vương Lâm"],"nguon":["@c1305"]},{"id":"dai-de-tinh","name":"Đại đế tinh","cn":"","aliases":["Điên Lạc đế tinh"],"capDo":"tinh-cau","parentId":"vung-dat-dien-lac","blurb":"Địa phương thần bí nhất vùng đất Điên Lạc, đồng thời là thánh địa của các bộ tộc trong vùng và động phủ của đại đế. Chỉ khi tuyển chọn trưởng lão Lạc Sinh hội mới mở thông đạo.","detail":"Đại đế tinh nổi tiếng trong Thái Cổ Tinh Thần, có hình dạng dị thường như đường thẳng hoặc kim la bàn, thường tồn tại từ lực và lực giằng xé áp chế pháp bảo cùng tu vi. Đây là thánh địa của các bộ tộc vùng đất Điên Lạc, là động phủ của đại đế và là nơi đoàn Vương Lâm hướng tới trong kỳ tuyển chọn trưởng lão Lạc Sinh hội.","theLucLienQuan":["Lạc Sinh hội","Các bộ tộc trong vùng đất Điên Lạc","Trường Tôn hội"],"nguon":["@c1305"]},{"id":"tinh-khong-ngoai-dai-de-tinh","name":"Tinh không ngoài Đại đế tinh","cn":"","capDo":"khac","parentId":"dai-de-tinh","blurb":"Tinh không ngoài Đại đế tinh là nơi nhiều vạn tu sĩ các tiểu tộc Điên Lạc tụ tập chờ thông đạo mở. Đây cũng là nơi xảy ra màn khiêu khích giữa Hồn Xà tộc, Hà tộc với các tộc hộ tống Vương Lâm.","detail":"Khu vực này nằm bên ngoài Đại đế tinh, nơi các nhóm tu sĩ tụ thành từng đám trước kỳ tuyển chọn trưởng lão Lạc Sinh hội. Tại đây, tộc trưởng Hà tộc cố lập uy, Long Giáp Tộc công khai bái kiến Vương Lâm, rồi thông đạo Đại đế tinh mở ra với sứ giả đại đế xuất hiện.","theLucLienQuan":["Lạc Sinh hội","Ám Hạt Tộc","Vân Độn tộc","Hồn Xà tộc","Hà tộc","Long Giáp Tộc"],"nguon":["@c1306"]},{"id":"vung-suong-mu-tu-luc-ngoai-thong-dao","name":"Vùng sương mù từ lực ngoài thông đạo","cn":"","capDo":"khac","parentId":"tinh-khong-ngoai-dai-de-tinh","blurb":"Vùng sương mù từ lực bao quanh thông đạo vào Đại đế tinh, nguy hiểm hơn lực hút bên trong thông đạo. Vương Lâm dùng nơi này để khiêu khích Tư Mặc Tử tự hủy tu vi thiên nhân ngũ suy rồi vào giao chiến.","detail":"Khu vực sương mù từ lực nằm ngoài thông đạo vào Đại đế tinh, có lực hút kinh khủng hơn trong thông đạo. Khi đối đầu Tư Mặc Tử, Vương Lâm lấy điều kiện tiến vào vùng này và tự hủy tu vi thiên nhân ngũ suy để chặn lời thách chiến của đối phương.","theLucLienQuan":["Vùng đất Điên Lạc"],"nguon":["@c1307"]},{"id":"truong-dau-tuyen-chon-truong-lao-lac-sinh-hoi","name":"Trường đấu tuyển chọn trưởng lão Lạc Sinh hội","cn":"","capDo":"khac","parentId":"dai-de-tinh","blurb":"Khu đất trống rộng khoảng ngàn dặm ở phía tây bắc Đại đế tinh, dùng cho tuyển chọn trưởng lão Lạc Sinh hội. Nơi này được bao phủ bởi vô số cấm chế, trong đó Vương Lâm nhận ra dấu hiệu Cổ Hồn cấm.","detail":"Trường đấu là địa điểm tuyển chọn trưởng lão Lạc Sinh hội vào ngày hôm sau. Khi Vương Lâm chạm tay dò xét, lực lượng cấm chế phản chấn hắn lùi lại và sau đó bị Lôi đồ ép hiện hình thành rùa xám khổng lồ.","theLucLienQuan":["Lạc Sinh hội","Điên Lạc đại đế"],"nguon":["@c1308"]},{"id":"truong-dau-lon-tren-dai-de-tinh","name":"Trường đấu lớn trên Đại đế tinh","cn":"","capDo":"khac","parentId":"dai-de-tinh","blurb":"Trường đấu lớn trên Đại đế tinh là nơi con rùa cấm chế khổng lồ tiêu tan, khiến Vương Lâm nhận ra dấu vết Cổ Hồn cấm.","detail":"Đây là khu vực Vương Lâm rời đi sau khi thấy bố trí cấm chế quy mô lớn. Sự kiện tại đây mở đầu cho chuỗi suy đoán của hắn về Cổ Hồn cấm và sự quỷ dị của Đại đế tinh.","theLucLienQuan":["Thế lực của đại đế"],"nguon":["@c1309"]},{"id":"khu-tay-bac-dai-de-tinh","name":"Khu tây bắc Đại đế tinh","cn":"","capDo":"khac","parentId":"dai-de-tinh","blurb":"Khu tây bắc Đại đế tinh là vùng mặt đất thưa thớt thực vật, nơi Vương Lâm hạ xuống lấy bùn đất đầu tiên để quan sát.","detail":"Từ nơi này, Vương Lâm bắt đầu đối chiếu cấu tạo bùn đất trên Đại đế tinh với hiểu biết từng có khi Thiên Nghịch mở ra.","theLucLienQuan":[],"nguon":["@c1309"]},{"id":"khu-dong-dai-de-tinh","name":"Khu đông Đại đế tinh","cn":"","capDo":"khac","parentId":"dai-de-tinh","blurb":"Khu đông Đại đế tinh là vùng tràn ngập thực vật vô tận, nơi Vương Lâm ngồi trên một tấm lá lớn để tiếp tục nghiên cứu bùn đất.","detail":"Tại đây, Vương Lâm vừa nghiên cứu dấu vết năm tháng của đất vừa phát hiện lá cây có thể hút đi một tia nguyên lực yếu ớt từ tay hắn.","theLucLienQuan":[],"nguon":["@c1309"]},{"id":"ho-nuoc-giua-thuc-vat","name":"Hồ nước giữa thực vật","cn":"","capDo":"khac","parentId":"dai-de-tinh","blurb":"Hồ nước giữa thực vật là nơi Vương Lâm gặp lão giả mặc bạch y câu cá dưới ánh trăng.","detail":"Hồ bị vô số thực vật vây quanh, mặt nước gợn sóng dưới gió nhẹ và trăng sáng. Lão giả bạch y ngồi câu cá bên hồ, cạnh đó có bầu rượu, rồi mở lời hỏi Vương Lâm có uống rượu không.","theLucLienQuan":[],"nguon":["@c1309"]},{"id":"lung-cu-quy","name":"Lưng cự quy","cn":"","capDo":"khac","parentId":"dai-de-tinh","blurb":"Không gian nghi thức nơi Lão Chu Tước mở thí luyện thiếu đế. Ba cây hương khổng lồ hiện ra tại đây, khiến lưng cự quy giống như một tế đàn lớn.","detail":"Lưng cự quy là nơi Lão Chu Tước hô dâng hương và làm xuất hiện ba cây hương Thiên, Địa, Nhân. Vương Lâm được cuồng phong đưa tới cây hương thứ nhất tại không gian này trước khi hồn phách nhập Nhân giới huyễn cảnh.","theLucLienQuan":["Chu Tước tộc","Vùng đất Điên Lạc"],"nguon":["@c1314"]},{"id":"nhan-phuong-gioi","name":"Nhân phương giới","cn":"","aliases":["Nhân giới huyễn cảnh","Nhân giới trong Thiên, Địa, Nhân","Nhân giới trong hồn Vương Lâm","Nhân giới","Nhân phương giới / Nhân giới"],"capDo":"gioi-nho","parentId":"vung-dat-dien-lac","blurb":"Huyễn giới thứ nhất trong thí luyện Thiên, Địa, Nhân của vùng đất Điên Lạc. Nơi này hiện thành một thành trì phàm nhân mờ ảo như mộng khi Vương Lâm nhập cây hương thứ nhất.","detail":"Nhân phương giới trong chương này biểu hiện thành Nhân giới huyễn cảnh, có cầu, sông, phố xá, tiếng rao, thuyền lớn và người qua lại. Vương Lâm nhận ra mọi vật ở đây đều hư ảo, nhưng thanh niên trên thuyền lại khiến hắn chấn động vì dung mạo quen thuộc.","theLucLienQuan":["Vùng đất Điên Lạc"],"nguon":["@c1314"]},{"id":"thanh-tri-pham-nhan-trong-nhan-gioi","name":"Thành trì phàm nhân trong Nhân giới","cn":"","capDo":"thanh","parentId":"nhan-phuong-gioi","blurb":"Bối cảnh phàm nhân trong Nhân giới huyễn cảnh, nơi Vương Lâm đứng trên cầu và nhìn thấy sông, phố xá, thuyền cùng người qua lại. Cảnh vật ở đây mơ hồ như mộng, thiếu cảm giác chân thật.","detail":"Thành trì phàm nhân trong Nhân giới có đường phố, hàng rong, tiếng rao bán, dòng sông và thuyền lớn chở thanh niên uống rượu. Đây là lớp cảnh đầu tiên Vương Lâm nhìn thấy sau khi hồn phách tiến vào cây hương thứ nhất.","theLucLienQuan":[],"nguon":["@c1314"]},{"id":"cay-huong-thu-nhat-tren-lung-cu-quy","name":"Cây hương thứ nhất trên lưng cự quy","cn":"","capDo":"khac","parentId":"lung-cu-quy","blurb":"Vị trí đặt Nhân phương hương trên lưng cự quy ở Đại đế tinh. Đây là nơi biểu hiện trực tiếp biến hóa trong Nhân phương giới khi Vương Lâm đốt hương.","detail":"Cây hương thứ nhất trên lưng cự quy bốc khói đen rồi cháy bùng dữ dội sau khi Vương Lâm dẫn nghiệp hỏa trong Nhân phương giới công kích thiên không. Ngọn lửa thiêu đốt cực nhanh, khiến mấy vạn tu sĩ và các cường giả trên Đại đế tinh chấn động.","theLucLienQuan":["Vùng đất Điên Lạc"],"nguon":["@c1318"]},{"id":"dia-phuong-gioi","name":"Địa Phương giới","cn":"","capDo":"gioi-nho","parentId":"dai-de-tinh","blurb":"Không gian thí luyện thứ hai trong ba cây hương Thiên Địa Nhân trên Đại đế tinh. Vùng đất nứt nẻ mênh mông nơi Vương Lâm chịu Cửu Chuyển Nghiệp Kiếp chín màu và Chu Tước tỉnh giấc lần thứ tư.","detail":"Địa Phương giới là không gian liên thông với Địa Phương hương, nơi Vương Lâm phá bầu trời Nhân Phương giới lao vào. Vùng đất mênh mông nứt nẻ với ngọn núi trọc ở tận cùng nơi nam tử trung niên mặc văn bào ngồi. Tại đây ba màu lửa thanh, lam, tím kéo tới hợp với bốn ngọn lửa trong thân Vương Lâm hình thành kiếp hỏa bảy màu, sau đó hai kiếp đen trắng giáng xuống hoàn chỉnh Cửu Chuyển Nghiệp Kiếp, Thiên Nghịch tái hiện và Chu Tước chín màu tỉnh giấc.","theLucLienQuan":["Chu Tước tộc"],"nguon":["@c1320"]},{"id":"ngon-nui-troc-dia-phuong-gioi","name":"Ngọn núi trọc tận cùng Địa Phương giới","cn":"","capDo":"khac","parentId":"dia-phuong-gioi","blurb":"Ngọn núi trọc ở tận cùng mặt đất Địa Phương giới, nơi nam tử trung niên mặc văn bào ngồi suốt thời gian dài và từ đó phóng ấn ký Chu Tước cứu viện Vương Lâm.","detail":"Nằm ở vị trí tận cùng trong Địa Phương giới. Nam tử trung niên có Chu Tước hư ảo ở mi tâm ngồi tại đây, nhận ra khí tức tộc nhân khi Vương Lâm xuất hiện và phóng ấn ký cứu viện nhưng bị sức mạnh Thiên Nghịch đánh bật.","theLucLienQuan":["Chu Tước tộc"],"nguon":["@c1320"]},{"id":"viem-vuc","name":"Viêm vực","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi viêm long từng sống khi còn nhỏ trước khi bị Chu Tước đời đầu lừa ra ngoài.","detail":"Viêm vực là chỗ ở ban đầu của viêm long. Năm xưa Chu Tước đời đầu đã lừa viêm long ra khỏi viêm vực khi nó còn nhỏ để liên tục lấy máu.","theLucLienQuan":[],"nguon":["@c1321"]},{"id":"dau-truong-dai-de-tinh","name":"Đấu trường","cn":"","capDo":"khac","parentId":"dai-de-tinh","blurb":"Nơi Địa phương hương gãy rơi xuống sau khi xuyên qua cự quy.","detail":"Đấu trường trên Đại đế tinh, nơi mấy vạn tu sĩ quan sát thí luyện và chứng kiến Địa phương hương gãy đổ rơi xuống.","theLucLienQuan":[],"nguon":["@c1323"]},{"id":"son-thon-que-cu-vuong-lam","name":"Sơn thôn","cn":"山村","capDo":"khac","parentId":"trieu-quoc-map","blurb":"Sơn thôn quê cũ trong huyễn cảnh cửa Nhân, gắn với thân thế phàm tục của Vương Lâm — nơi hắn đứng trên Hằng Nhạc phái nhìn xuống và rời đi trong nước mắt.","detail":"Quê cũ của Vương Lâm trong huyễn cảnh, nơi cha Vương Thiên Thủy làm nghề thợ mộc. Vương Lâm đứng trên Hằng Nhạc phái nhìn sơn thôn phía dưới, nước mắt chảy dài trước khi xoay người rời đi.","theLucLienQuan":[],"nguon":["@c1315"]},{"id":"hoa-phan-quoc","name":"Hỏa Phần quốc","cn":"火焚国","capDo":"quoc-gia","parentId":"chu-tuoc-tinh","blurb":"Quốc gia trong huyễn cảnh cửa Nhân, nơi Lạc Hà môn tọa lạc và cảnh Lý Mộ Uyển thời thiếu nữ luyện đan hiện ra.","detail":"Trong huyễn cảnh Nhân giới, Hỏa Phần quốc là nơi có Lạc Hà môn — tông môn của Lý Mộ Uyển thời thiếu nữ.","theLucLienQuan":["Lạc Hà môn"],"nguon":["@c1315"]},{"id":"hang-nhac-phai-map","name":"Hằng Nhạc phái","cn":"恒岳派","capDo":"khac","parentId":"trieu-quoc-map","blurb":"Tông môn gần sơn thôn quê cũ Vương Lâm trong huyễn cảnh cửa Nhân.","detail":"Vương Lâm đứng trên Hằng Nhạc phái nhìn sơn thôn phía dưới trong huyễn cảnh, rồi xoay người rời đi trong nước mắt.","theLucLienQuan":["Hằng Nhạc phái"],"nguon":["@c1315"]},{"id":"lac-ha-mon-map","name":"Lạc Hà môn","cn":"落河门","capDo":"khac","parentId":"hoa-phan-quoc","blurb":"Tông môn ở Hỏa Phần quốc trong huyễn cảnh cửa Nhân, nơi Lý Mộ Uyển thiếu nữ luyện đan thất bại.","detail":"Trong huyễn cảnh Nhân giới, Lạc Hà môn hiện ra với đan phòng phía sau núi và dược phong nơi Uyển nhi được sai đi lấy Thủy Nguyệt thảo.","theLucLienQuan":["Lạc Hà môn"],"nguon":["@c1315"]}]};
